type LangMap = { en: string; ms: string; tur: string; urd: string; ben: string; fas: string; zh: string; yue: string; ja: string; ru: string; es: string; ko: string; ta: string; si: string };
export type SalaatFardKey = keyof typeof SALAAT_FARD_CONTENT;

/**
 * Per-prayer keys (for each of the 5 fard) follow this naming:
 *   <id>_name, <id>_when, <id>_structure, <id>_story, <id>_significance,
 *   <id>_proof_q, <id>_proof_h, <id>_recitation, <id>_fard_say,
 *   <id>_sunnah_say, <id>_extras_say, <id>_virtues, <id>_timing_notes
 * Universal keys (the things said in EVERY prayer regardless of which fard):
 *   uni_section_h, uni_fard_h, uni_fard_body,
 *   uni_wajib_h, uni_wajib_body, uni_sunnah_h, uni_sunnah_body,
 *   uni_extras_h, uni_extras_body
 */
export const SALAAT_FARD_CONTENT = {
  /* ── Page section header ──────────────────────────────────── */
  section_h: { en: `The Five Daily Prayers (Salawat al-Khams)`, ms: `Lima Solat Fardu (Solat al-Khams)`, tur: `Beş Vakit Namaz (Salavâtü'l-Hams)`, urd: `پانچ فرض نمازیں (صلوات الخمس)`, ben: `পাঁচ ওয়াক্ত নামাজ (সালাওয়াত আল-খামস)`, fas: `پنج نماز فرض (صلوات الخمس)`, zh: `五次主命拜功（Salawat al-Khams）`, yue: `五次主命拜功（Salawat al-Khams）`, ja: `五時の義務礼拝（サラワート・アル＝ハムス）`, ru: `Пять обязательных молитв (Салават аль-Хамс)`, es: `Las cinco oraciones obligatorias (Salawat al-Khams)`, ko: `다섯 의무 예배 (살라와트 알함스)`, ta: `ஐந்து கடமைத் தொழுகைகள் (ஸலவாத் அல்-கம்ஸ்)`, si: `පංච අනිවාර්ය සලාත (සලවාත් අල්-කම්ස්)` },
  section_intro: { en: `The five daily prayers are the second pillar of Islam and the first deed a servant will be questioned about on the Day of Judgement. They were ordained directly from Allah to the Prophet ﷺ on the Night of the Ascension (Al-Mi'raj) without any intermediary  –  a distinction held by no other act of worship.`, ms: `Lima solat sehari semalam adalah rukun Islam yang kedua dan amalan pertama yang akan ditanyakan kepada hamba pada Hari Pembalasan. Ia diwajibkan terus daripada Allah kepada Nabi ﷺ pada malam Isra' dan Mi'raj tanpa sebarang perantara  –  suatu kelebihan yang tidak dimiliki oleh sebarang ibadah lain.`, tur: `Beş vakit namaz, İslam'ın ikinci şartıdır ve Kıyamet Günü kuldan ilk sorulacak ameldir. Mi'rac gecesinde aracısız olarak doğrudan Allah'tan Peygamber'e ﷺ farz kılınmıştır  –  başka hiçbir ibadetin sahip olmadığı bir ayrıcalıktır.`, urd: `پانچ وقت کی نمازیں اسلام کا دوسرا رکن ہیں اور قیامت کے دن بندے سے سب سے پہلے جس عمل کا سوال ہو گا۔ یہ شب معراج میں اللہ نے بغیر کسی واسطے کے براہِ راست نبی ﷺ کو عطا کیں  –  ایک امتیاز جو کسی اور عبادت کو حاصل نہیں۔`, ben: `পাঁচ ওয়াক্ত নামাজ ইসলামের দ্বিতীয় স্তম্ভ এবং কিয়ামতের দিনে বান্দার কাছে যে আমলের কথা প্রথম জিজ্ঞাসা করা হবে। এগুলো মেরাজের রাতে কোনো মাধ্যম ছাড়াই সরাসরি আল্লাহ থেকে নবী ﷺ-কে ফরজ করা হয়েছিল  –  এমন বৈশিষ্ট্য আর কোনো ইবাদতের নেই।`, fas: `پنج نماز روزانه دومین رکن اسلام و نخستین عملی است که در روز قیامت از بنده پرسیده می‌شود. این نمازها در شب معراج، بدون هیچ واسطه، مستقیماً از خداوند بر پیامبر ﷺ فرض شد  –  امتیازی که هیچ عبادت دیگری ندارد.`, zh: `五次日常拜功是伊斯兰的第二支柱，也是仆人在审判日首先被问及的功修。它们在登霄之夜由真主无任何中介直接降命于先知ﷺ  –  此为其他功修所未享之殊荣。`, yue: `五次日常拜功係伊斯蘭嘅第二支柱，亦係僕人喺審判日首先被問及嘅功修。佢哋喺登霄之夜由真主無任何中介直接降命於先知ﷺ  –  此為其他功修所未享之殊榮。`, ja: `五時の毎日礼拝はイスラムの第二の柱であり、審判の日にしもべが最初に問われる行為です。ミウラージ（昇天）の夜に、いかなる仲介者もなく直接アッラーから預言者ﷺに義務として課されました  –  他のいかなる崇拝行為にも与えられていない栄誉です。`, ru: `Пять ежедневных молитв  –  второй столп ислама и первое, о чём раб будет спрошен в Судный день. Они были предписаны напрямую от Аллаха Пророку ﷺ в Ночь Вознесения (аль-Мирадж) без какого-либо посредника  –  отличие, которого не имеет ни одно другое богослужение.`, es: `Las cinco oraciones diarias son el segundo pilar del islam y la primera obra por la que se preguntará al siervo el Día del Juicio. Fueron ordenadas directamente por Allah al Profeta ﷺ en la Noche de la Ascensión (Al-Mi'raj) sin intermediario alguno  –  un honor que no tiene ningún otro acto de adoración.`, ko: `다섯 번의 일일 예배는 이슬람의 두 번째 기둥이며 심판의 날에 종이 가장 먼저 질문받게 될 행위입니다. 미으라즈(승천)의 밤에 어떠한 중개자도 없이 알라께서 직접 예언자 ﷺ께 의무로 정하셨습니다  –  그 어떤 다른 예배 행위에도 없는 영예입니다.`, ta: `ஐந்து வேளைத் தொழுகைகள் இஸ்லாத்தின் இரண்டாவது தூணும், மறுமை நாளில் அடியானிடம் முதலில் கேட்கப்படும் செயலும் ஆகும். மிஃராஜ் இரவில் எவ்வித இடைத்தரகனுமின்றி அல்லாஹ்விடமிருந்து நேரடியாக நபி ﷺ அவர்களுக்கு கடமையாக்கப்பட்டது  –  வேறு எந்த வணக்கத்திற்கும் இல்லாத ஒரு சிறப்பு.`, si: `පංච දෛනික සලාත ඉස්ලාමයේ දෙවන කණුව වන අතර, විනිශ්චය දිනයේ දාසයාගෙන් මුලින්ම විමසනු ලබන ක්‍රියාවද වේ. මිඃරාජ් (ස්වර්ගාරෝහණ) රාත්‍රියේදී කිසිදු මැදිහත්කරුවෙකු නොමැතිව අල්ලාහ්ගෙන් සෘජුවම නබි ﷺ වෙත අනිවාර්ය කෙරුණි  –  වෙනත් කිසිදු නැමදුම් ක්‍රියාවකට නොලැබුණු ගෞරවයකි.` },

  /* ── Universal: what is said in every prayer ──────────────── */
  uni_section_h: { en: `What Is Said in Every Prayer`, ms: `Apa yang Dibaca dalam Setiap Solat`, tur: `Her Namazda Okunanlar`, urd: `ہر نماز میں کیا پڑھا جاتا ہے`, ben: `প্রতিটি নামাজে যা পড়া হয়`, fas: `آنچه در هر نماز خوانده می‌شود`, zh: `每次拜功中所诵读的内容`, yue: `每次拜功中所誦讀嘅內容`, ja: `すべての礼拝で唱えること`, ru: `Что произносится в каждой молитве`, es: `Lo que se recita en cada oración`, ko: `모든 예배에서 낭송하는 것`, ta: `ஒவ்வொரு தொழுகையிலும் ஓதப்படுவன`, si: `සෑම සලාතයකම කියවන දෑ` },

  uni_fard_h: { en: `Fard (Compulsory)  –  the prayer is invalid without these`, ms: `Fardu (Wajib mutlak)  –  solat tidak sah tanpa ini`, tur: `Farz (Mutlaka yapılması gereken)  –  bunlar olmadan namaz geçersizdir`, urd: `فرض (لازمی)  –  ان کے بغیر نماز باطل ہے`, ben: `ফরজ (অপরিহার্য)  –  এগুলো ছাড়া নামাজ বাতিল`, fas: `فرض (واجب قطعی)  –  بدون اینها نماز باطل است`, zh: `主命（绝对必行）  –  缺此则拜功无效`, yue: `主命（絕對必行）  –  缺此則拜功無效`, ja: `ファルド（絶対の義務）  –  これらがなければ礼拝は無効`, ru: `Фард (обязательное)  –  без этого молитва недействительна`, es: `Fard (obligatorio)  –  sin esto la oración es inválida`, ko: `파르드(필수)  –  이것 없이는 예배가 무효`, ta: `ஃபர்ள் (கட்டாயம்)  –  இவையின்றி தொழுகை செல்லாது`, si: `ෆර්ද් (අත්‍යවශ්‍ය)  –  මේවා නැතිව සලාතය වලංගු නොවේ` },
  uni_fard_body: { en: `1) Standing (qiyam) if able. 2) Opening Takbir (Allahu Akbar)  –  the prayer begins with it. 3) Reciting Surah al-Fatihah in every rak'ah. 4) Bowing (ruku') with reassurance (tuma'ninah). 5) Standing erect after ruku' (i'tidal). 6) Two prostrations (sujud) on the seven body parts: forehead with nose, two palms, two knees, and the toes of both feet. 7) Sitting briefly between the two prostrations (jalsah). 8) The final sitting and the testimony (tashahhud al-akhir). 9) The closing salam to the right and left. 10) Proper order (tartib) of all these. Any one of these omitted invalidates the prayer.`, ms: `1) Berdiri (qiyam) jika mampu. 2) Takbir pembukaan (Allahu Akbar)  –  solat bermula dengannya. 3) Membaca Surah al-Fatihah dalam setiap rakaat. 4) Rukuk dengan tenang (tumakninah). 5) Berdiri tegak selepas rukuk (i'tidal). 6) Dua kali sujud di atas tujuh anggota: dahi bersama hidung, dua tapak tangan, dua lutut, dan jari-jari kedua kaki. 7) Duduk seketika antara dua sujud (jalsah). 8) Duduk akhir dan membaca tasyahhud akhir. 9) Memberi salam ke kanan dan ke kiri. 10) Tertib semua ini. Jika satu daripadanya tertinggal, solat menjadi batal.`, tur: `1) Gücü yeten için kıyam. 2) İftitah tekbiri (Allahu Ekber)  –  namaz onunla başlar. 3) Her rekâtta Fâtiha okumak. 4) Tumâninetle rükû. 5) Rükûdan doğrularak dik durmak (i'tidâl). 6) Yedi azâ üzerine secde: burunla birlikte alın, iki avuç, iki diz ve iki ayağın parmakları. 7) İki secde arasında kısa oturuş (celse). 8) Son oturuş ve son tahiyyât. 9) Sağa ve sola selam vermek. 10) Bunların hepsinin tertibi. Birinin terki namazı batıl kılar.`, urd: `(۱) قدرت ہو تو قیام۔ (۲) تکبیرِ تحریمہ (اللہ اکبر)  –  نماز اسی سے شروع ہوتی ہے۔ (۳) ہر رکعت میں سورۃ الفاتحہ پڑھنا۔ (۴) اطمینان کے ساتھ رکوع۔ (۵) رکوع کے بعد سیدھا کھڑا ہونا (اعتدال)۔ (۶) سات اعضاء پر سجدہ: ناک کے ساتھ پیشانی، دونوں ہتھیلیاں، دونوں گھٹنے، اور دونوں پاؤں کی انگلیاں۔ (۷) دو سجدوں کے درمیان مختصر بیٹھنا (جلسہ)۔ (۸) آخری قعدہ اور تشہّدِ آخر۔ (۹) دائیں اور بائیں سلام پھیرنا۔ (۱۰) ان سب کی ترتیب۔ ان میں سے کوئی ایک بھی چھوٹ جائے تو نماز باطل۔`, ben: `১) সক্ষম হলে দাঁড়ানো (কিয়াম)। ২) তাকবিরে তাহরিমা (আল্লাহু আকবার)  –  নামাজ এর দ্বারা শুরু হয়। ৩) প্রতি রাকাতে সূরা আল-ফাতিহা পড়া। ৪) তুমানিনার সাথে রুকু। ৫) রুকুর পর সোজা দাঁড়ানো (ই'তিদাল)। ৬) সাত অঙ্গে সিজদা: নাকসহ কপাল, দুই হাতের তালু, দুই হাঁটু এবং উভয় পায়ের আঙুল। ৭) দুই সিজদার মাঝে সংক্ষিপ্ত বসা (জলসা)। ৮) শেষ বৈঠক ও শেষ তাশাহহুদ। ৯) ডানে ও বামে সালাম ফেরানো। ১০) এসবের ক্রমধারা (তরতীব)। এর কোনো একটি ছুটে গেলে নামাজ বাতিল।`, fas: `۱) قیام در صورت توان. ۲) تکبیرة الاحرام (الله اکبر)  –  نماز با آن آغاز می‌شود. ۳) خواندن سوره فاتحه در هر رکعت. ۴) رکوع با اطمینان (طمأنینه). ۵) ایستادن راست پس از رکوع (اعتدال). ۶) دو سجده بر هفت عضو: پیشانی همراه بینی، دو کف دست، دو زانو و انگشتان دو پا. ۷) نشستن کوتاه میان دو سجده (جلسه). ۸) نشستن آخر و تشهد آخر. ۹) سلام به راست و چپ. ۱۰) ترتیب همه اینها. ترک یکی، نماز را باطل می‌کند.`, zh: `(一)能立则立（吉亚姆）。(二)开始的大赞词（安拉至大）  –  拜功由此开始。(三)每一拜中诵读《开端章》。(四)从容地鞠躬（鲁库）。(五)鞠躬后挺立（伊提达勒）。(六)以七处叩头：额并鼻、两掌、两膝、两足趾。(七)两次叩头之间短暂端坐（杰勒赛）。(八)末次端坐与末次的作证词（塔沙胡德）。(九)向右与向左道平安。(十)以上的顺序（特尔提卜）。缺其中一项则拜功无效。`, yue: `(一)能立則立（吉亞姆）。(二)開始嘅大讚詞（安拉至大）  –  拜功由此開始。(三)每一拜中誦讀《開端章》。(四)從容噉鞠躬（魯庫）。(五)鞠躬後挺立（伊提達勒）。(六)以七處叩頭：額連鼻、兩掌、兩膝、兩足趾。(七)兩次叩頭之間短暫端坐（傑勒賽）。(八)末次端坐同末次嘅作證詞（塔沙胡德）。(九)向右與向左道平安。(十)以上嘅順序（特爾提卜）。缺其中一項則拜功無效。`, ja: `(1) 可能であれば立つこと（キヤーム）。(2) 開始のタクビール（アッラーフ・アクバル）  –  礼拝はこれにより始まる。(3) 各ラクアでファーティハ章を朗誦。(4) 落ち着いて立礼（ルクー）。(5) ルクー後に真っ直ぐ立つ（イーティダール）。(6) 七つの部位での平伏（スジュード）：鼻とともに額、両手のひら、両膝、両足のつま先。(7) 二度の平伏の間の短い座（ジャルサ）。(8) 最後の座と最後のタシャフード。(9) 右と左へのサラーム。(10) これらすべての順序（タルティーブ）。一つでも欠けると礼拝は無効。`, ru: `1) Стояние (кыям), если способен. 2) Открывающий такбир (Аллаху Акбар)  –  молитва начинается с него. 3) Чтение суры аль-Фатиха в каждом ракате. 4) Поясной поклон (руку') с упокоением (тумаъанина). 5) Прямое стояние после руку' (и'тидаль). 6) Два земных поклона (суджуд) на семи частях тела: лоб с носом, две ладони, два колена и пальцы обеих стоп. 7) Краткое сидение между двумя суджудами (джалса). 8) Окончательное сидение и последнее свидетельство (ташаххуд). 9) Завершающий салам направо и налево. 10) Должный порядок (тартиб) всего этого. Пропуск любого из них делает молитву недействительной.`, es: `1) Estar de pie (qiyam) si se puede. 2) Takbir de apertura (Allahu Akbar)  –  la oración comienza con él. 3) Recitar la Sura al-Fatiha en cada rak'ah. 4) Inclinación (ruku') con sosiego (tuma'ninah). 5) Erguirse tras el ruku' (i'tidal). 6) Dos prosternaciones (sujud) sobre siete miembros: frente con la nariz, las dos palmas, las dos rodillas y los dedos de ambos pies. 7) Sentarse brevemente entre las dos prosternaciones (jalsah). 8) Sentada final y el testimonio (tashahhud al-akhir). 9) Salam final a derecha e izquierda. 10) Orden adecuado (tartib) de todo ello. Omitir cualquiera invalida la oración.`, ko: `1) 가능하면 서기(끼얌). 2) 시작의 타크비르(알라후 아크바르)  –  예배는 이것으로 시작된다. 3) 각 라카에서 알파티하 장 낭송. 4) 안정함(투마으니나)을 가진 절(루쿠으). 5) 루쿠으 뒤에 곧게 서기(이으티달). 6) 일곱 부위로 엎드림(수주드): 코와 함께 이마, 두 손바닥, 두 무릎, 양발의 발가락. 7) 두 엎드림 사이의 짧은 앉음(잘사). 8) 마지막 앉음과 최후의 증언(타샤후드). 9) 오른쪽과 왼쪽으로 마치는 살람. 10) 이 모두의 순서(타르티브). 어느 하나라도 빠지면 예배는 무효.`, ta: `1) இயலுமாயின் நிற்றல் (கியாம்). 2) தொடக்கத் தக்பீர் (அல்லாஹு அக்பர்)  –  தொழுகை இதனால் தொடங்குகிறது. 3) ஒவ்வொரு ரக்அத்திலும் சூரத்துல் ஃபாதிஹா ஓதுதல். 4) நிதானத்துடன் (துமஃனீனா) ருகூஉ. 5) ருகூஉவுக்குப் பின் நேராக நிற்றல் (இஃதிதால்). 6) ஏழு உறுப்புகளில் சுஜூத்: மூக்குடன் நெற்றி, இரு உள்ளங்கைகள், இரு முழங்கால்கள், இரு கால்களின் விரல்கள். 7) இரு சுஜூதுகளுக்கு இடையே குறுகிய இருப்பு (ஜல்ஸா). 8) இறுதி இருப்பு மற்றும் இறுதி தஷஹ்ஹுத். 9) வலதிலும் இடதிலும் முடிவுச் ஸலாம். 10) இவ்வனைத்தின் ஒழுங்கு (தர்த்தீப்). எதையேனும் விட்டால் தொழுகை செல்லாது.`, si: `1) හැකි නම් සිටගැනීම (කියාම්). 2) ආරම්භක තක්බීර (අල්ලාහු අක්බර්)  –  සලාතය එයින් ආරම්භ වේ. 3) සෑම රකඅතකම අල්-ෆාතිහා සූරාව කියවීම. 4) සන්සුන්කමින් (තුමඃනීනා) රුකූඃ. 5) රුකූඃ පසු සෘජුව සිටගැනීම (ඉඃතිදාල්). 6) අංග හතක් මත සජ්දා: නාසය සමඟ නළල, දෑත් අල්ල, දෙදන, දෙපාදයේ ඇඟිලි. 7) සජ්දා දෙක අතර කෙටි ඉඳීම (ජල්සා). 8) අවසන් ඉඳීම සහ අවසන් තශහ්හුද්. 9) දකුණට හා වමට අවසන් සලාම්. 10) මේ සියල්ලෙහි පිළිවෙළ (තර්තීබ්). කවරයක් හෝ අත්හැරියහොත් සලාතය වලංගු නොවේ.` },

  uni_wajib_h: { en: `Wajib  –  necessary; omission requires sajdat al-sahw`, ms: `Wajib  –  perlu; jika tertinggal hendaklah sujud sahwi`, tur: `Vacip  –  gerekli; terki sehiv secdesini gerektirir`, urd: `واجب  –  ضروری؛ ترک پر سجدہ سہو لازم`, ben: `ওয়াজিব  –  জরুরি; ছুটে গেলে সিজদা সাহু আবশ্যক`, fas: `واجب  –  لازم؛ ترک آن، سجده سهو می‌خواهد`, zh: `当然（Wajib）  –  必要的；遗漏须行忘记叩头（萨乎叩头）`, yue: `當然（Wajib）  –  必要嘅；遺漏須行忘記叩頭（薩乎叩頭）`, ja: `ワージブ  –  必要；省略時はサジダ・アッ＝サハウ（忘却の平伏）が必要`, ru: `Ваджиб  –  необходимое; пропуск требует саджда ас-сахв (земной поклон забывчивости)`, es: `Wajib  –  necesario; su omisión exige la sajdat al-sahw (prosternación del olvido)`, ko: `와집  –  필수; 누락 시 사즈다 사후(망각의 엎드림) 요구됨`, ta: `வாஜிப்  –  அவசியம்; தவறினால் ஸஜ்தத்துல் ஸஹ்வ் தேவை`, si: `වාජිබ්  –  අවශ්‍ය; අත්හැරියහොත් සජ්දත් අස්-සහ්ව් අවශ්‍යය` },
  uni_wajib_body: { en: `1) Reciting a surah or three short verses after Fatihah in the first two rak'ahs. 2) The opening hand-raising and the takbirs of transition between postures. 3) Saying "Sami'allahu liman hamidah" (the imam and the lone worshipper) and "Rabbana wa lakal-hamd" (everyone) when rising from ruku'. 4) The tasbih in ruku' ("Subhana Rabbiyal-'Azim") and sujud ("Subhana Rabbiyal-A'la") at least once  –  three times being the minimum sunnah. 5) The first tashahhud (in 3- or 4-rak'ah prayers). 6) Salawat upon the Prophet ﷺ in the final tashahhud. 7) Both salams. If a wajib is forgotten, the prayer is still valid, and the worshipper performs two extra prostrations of forgetfulness (sajdat al-sahw) before or after the salam.`, ms: `1) Membaca surah atau tiga ayat pendek selepas Fatihah pada dua rakaat pertama. 2) Mengangkat tangan pembukaan dan takbir-takbir intiqal (peralihan posisi). 3) Mengucap "Sami'allahu liman hamidah" (imam dan munfarid) serta "Rabbana wa lakal-hamd" (semua) ketika bangkit dari rukuk. 4) Tasbih dalam rukuk ("Subhana Rabbiyal-'Azim") dan sujud ("Subhana Rabbiyal-A'la") sekurang-kurangnya sekali  –  tiga kali adalah sunnah minimum. 5) Tasyahhud awal (dalam solat 3 atau 4 rakaat). 6) Selawat ke atas Nabi ﷺ pada tasyahhud akhir. 7) Kedua-dua salam. Jika satu wajib tertinggal, solat tetap sah dan dilakukan dua sujud sahwi sebelum atau selepas salam.`, tur: `1) İlk iki rekâtta Fâtiha'dan sonra bir sure veya üç kısa âyet okumak. 2) İftitahta el kaldırmak ve duruşlar arasındaki intikal tekbirleri. 3) Rükûdan kalkarken (imam ve munferid) "Semi'allâhu limen hamideh" ve (herkes) "Rabbenâ ve lekel-hamd" demek. 4) Rükûda ("Sübhâne Rabbiyel-Azîm") ve secdede ("Sübhâne Rabbiyel-A'lâ") en az bir kere tesbih  –  asgari sünnet üç defadır. 5) İlk tahiyyât (3 veya 4 rekâtlı namazlarda). 6) Son tahiyyâtta Peygamber'e ﷺ salavât. 7) Her iki selam. Vacip terkedilirse namaz yine geçerlidir; selamdan önce veya sonra iki sehiv secdesi yapılır.`, urd: `(۱) پہلی دو رکعتوں میں فاتحہ کے بعد ایک سورت یا تین چھوٹی آیات پڑھنا۔ (۲) تکبیرِ تحریمہ پر ہاتھ اٹھانا اور انتقال کی تکبیرات۔ (۳) رکوع سے اٹھتے ہوئے (امام و منفرد) "سمع اللہ لمن حمدہ" اور (سب) "ربنا و لک الحمد" کہنا۔ (۴) رکوع میں "سبحان ربی العظیم" اور سجدہ میں "سبحان ربی الاعلیٰ" کم از کم ایک بار  –  تین بار ادنیٰ سنت ہے۔ (۵) قعدہ اولیٰ (تین یا چار رکعتی نماز میں)۔ (۶) قعدہ اخیرہ میں نبی ﷺ پر درود۔ (۷) دونوں سلام۔ کوئی واجب رہ جائے تو نماز صحیح رہتی ہے، سلام سے پہلے یا بعد دو سجدہ سہو کیے جاتے ہیں۔`, ben: `১) প্রথম দুই রাকাতে ফাতিহার পরে একটি সূরা বা তিনটি ছোট আয়াত পড়া। ২) তাকবিরে তাহরিমার সময় হাত উঠানো ও অবস্থান পরিবর্তনের তাকবির। ৩) রুকু থেকে উঠার সময় (ইমাম ও একা পড়নেওয়ালা) "সামি'আল্লাহু লিমান হামিদাহ" এবং (সকলে) "রব্বানা ওয়া লাকাল-হামদ" বলা। ৪) রুকুতে "সুবহানা রব্বিয়াল-আজীম" ও সিজদায় "সুবহানা রব্বিয়াল-আ'লা" অন্তত একবার  –  তিনবার সর্বনিম্ন সুন্নাহ। ৫) প্রথম তাশাহহুদ (৩ বা ৪ রাকাতের নামাজে)। ৬) শেষ তাশাহহুদে নবী ﷺ-এর প্রতি দরুদ। ৭) উভয় সালাম। ওয়াজিব ছুটে গেলে নামাজ বহাল থাকে, সালামের আগে বা পরে দুটি সিজদা সাহু করতে হয়।`, fas: `۱) خواندن یک سوره یا سه آیه کوتاه پس از فاتحه در دو رکعت اول. ۲) بلندکردن دست در تکبیرة الاحرام و تکبیرات انتقال میان حالات. ۳) گفتن "سمع الله لمن حمده" (امام و منفرد) و "ربنا و لک الحمد" (همه) هنگام برخاستن از رکوع. ۴) تسبیح در رکوع ("سبحان ربی العظیم") و سجده ("سبحان ربی الأعلی") دست‌کم یک بار  –  سه بار حداقل سنت است. ۵) تشهد اول (در نماز سه یا چهار رکعتی). ۶) صلوات بر پیامبر ﷺ در تشهد آخر. ۷) هر دو سلام. اگر واجبی ترک شود نماز صحیح است و دو سجده سهو پیش یا پس از سلام انجام می‌گیرد.`, zh: `(一)前两拜中在《开端章》后诵读一章或三节短经。(二)开始的举手与转换体态时的大赞词。(三)起身于鞠躬时（伊玛目与独自礼者）念"赛米阿拉胡列曼哈米达"，（所有人）念"拉布巴那瓦勒卡勒哈姆德"。(四)鞠躬中念"苏布哈那拉比耶勒阿则姆"，叩头中念"苏布哈那拉比耶勒阿俩"至少一次  –  三次为最低圣行。(五)初次端坐之作证词（三拜或四拜的拜功中）。(六)末次端坐时向先知ﷺ的赞祷。(七)两次平安词。若遗漏某当然，拜功仍有效，礼者于平安词前或后行两次"忘记叩头"。`, yue: `(一)前兩拜中喺《開端章》後誦讀一章或三節短經。(二)開始嘅舉手同轉換體態時嘅大讚詞。(三)起身於鞠躬時（伊瑪目同獨自禮者）念"賽米阿拉胡列曼哈米達"，（所有人）念"拉布巴那瓦勒卡勒哈姆德"。(四)鞠躬中念"蘇布哈那拉比耶勒阿則姆"，叩頭中念"蘇布哈那拉比耶勒阿倆"至少一次  –  三次為最低聖行。(五)初次端坐之作證詞（三拜或四拜嘅拜功中）。(六)末次端坐時向先知ﷺ嘅讚禱。(七)兩次平安詞。若遺漏某當然，拜功仍有效，禮者於平安詞前或後行兩次「忘記叩頭」。`, ja: `(1) 最初の二ラクアでファーティハの後に章または短い三節を朗誦。(2) 開始の挙手と体勢移行のタクビール。(3) ルクーから起き上がる際、（イマームと単独礼拝者は）「サミアッラーフ・リマン・ハミダ」、（皆は）「ラッバナー・ワ・ラカル＝ハムド」と唱える。(4) ルクーでは「スブハーナ・ラッビヤル＝アズィーム」、スジュードでは「スブハーナ・ラッビヤル＝アアラー」を少なくとも一回  –  最低限のスンナは三回。(5) 第一タシャフード（三または四ラクアの礼拝で）。(6) 最後のタシャフードでの預言者ﷺへのサラワート。(7) 両方のサラーム。ワージブが省略されても礼拝は有効で、サラームの前後に二回のサジダ・アッ＝サハウ（忘却の平伏）を行う。`, ru: `1) Чтение суры или трёх коротких аятов после Фатихи в первых двух ракатах. 2) Открывающее воздевание рук и такбиры перехода между положениями. 3) Произнесение "Сами' Аллаху лиман хамидах" (имам и индивидуально молящийся) и "Раббана ва лакаль-хамд" (все) при подъёме из руку'. 4) Тасбих в руку' ("Субхана Рабби-аль-'Азим") и суджуде ("Субхана Рабби-аль-А'ля") хотя бы один раз  –  три раза  –  минимальная сунна. 5) Первый ташаххуд (в молитвах из 3 или 4 ракатов). 6) Салават Пророку ﷺ в последнем ташаххуде. 7) Оба салама. Если ваджиб забыт, молитва действительна; молящийся совершает два дополнительных земных поклона забывчивости (саджда ас-сахв) до или после салама.`, es: `1) Recitar una sura o tres versículos cortos tras la Fatiha en los dos primeros rak'ahs. 2) El alzar de manos de apertura y los takbires de transición entre posturas. 3) Decir "Sami'allahu liman hamidah" (el imam y el orante solitario) y "Rabbana wa lakal-hamd" (todos) al incorporarse del ruku'. 4) El tasbih en ruku' ("Subhana Rabbiyal-'Azim") y en sujud ("Subhana Rabbiyal-A'la") al menos una vez  –  tres veces es la sunnah mínima. 5) El primer tashahhud (en oraciones de 3 o 4 rak'ahs). 6) Salawat al Profeta ﷺ en el tashahhud final. 7) Ambos salames. Si se olvida un wajib, la oración sigue siendo válida y el orante realiza dos prosternaciones de olvido (sajdat al-sahw) antes o después del salam.`, ko: `1) 처음 두 라카에서 파티하 후 한 장 또는 짧은 세 구절 낭송. 2) 시작의 손 들기와 자세 전환의 타크비르. 3) 루쿠으에서 일어설 때 (이맘과 단독 예배자는) "사미알라후 리만 하미다", (모두는) "랍바나 와 라칼-함드"를 말함. 4) 루쿠으에서 "수브하나 랍비얄-아짐", 수주드에서 "수브하나 랍비얄-아을라"를 적어도 한 번  –  세 번이 최소 순나. 5) 첫 타샤후드(3 또는 4 라카의 예배에서). 6) 마지막 타샤후드에서 예언자 ﷺ에 대한 살라와트. 7) 두 살람. 와집을 잊으면 예배는 여전히 유효하며, 살람 전후로 두 번의 망각의 엎드림(사즈다 사후)을 행함.`, ta: `1) முதல் இரு ரக்அத்களில் ஃபாதிஹாவுக்குப் பின் ஒரு சூரா அல்லது மூன்று குறு வசனங்கள் ஓதுதல். 2) தொடக்கத்தில் கைகளை உயர்த்துதல் மற்றும் நிலை மாற்ற தக்பீர்கள். 3) ருகூஉவிலிருந்து எழும்போது (இமாமும் தனியாகத் தொழுபவரும்) "ஸமிஅல்லாஹு லிமன் ஹமிதஹ்" மற்றும் (அனைவரும்) "ரப்பனா வ லகல்-ஹம்த்" எனல். 4) ருகூஉவில் "ஸுப்ஹான ரப்பியல்-அழீம்" மற்றும் சுஜூதில் "ஸுப்ஹான ரப்பியல்-அஃலா" குறைந்தது ஒருமுறை  –  மூன்று முறை குறைந்தபட்ச சுன்னா. 5) முதல் தஷஹ்ஹுத் (3 அல்லது 4 ரக்அத் தொழுகைகளில்). 6) இறுதி தஷஹ்ஹுதில் நபி ﷺ மீது ஸலவாத். 7) இரண்டு ஸலாம்களும். வாஜிபை மறந்தால் தொழுகை செல்லும், ஸலாமுக்கு முன் அல்லது பின் இரு மறதிச் சுஜூதுகள் (ஸஜ்தத்துல் ஸஹ்வ்) செய்யப்படுகின்றன.`, si: `1) පළමු රකඅත් දෙකේදී ෆාතිහා පසු සූරාවක් හෝ කෙටි වැකි තුනක් කියවීම. 2) ආරම්භක අත් ඔසවීම සහ ඉරියව් මාරුවේ තක්බීර. 3) රුකූඃ වෙතින් නැගිට්ටවන විට (ඉමාම් සහ තනිව සලාත් කරන්නා) "සමි අල්ලාහු ලිමන් හමිදහ්", (සියලුදෙනා) "රබ්බනා ව ලකල්-හම්ද්" කීම. 4) රුකූඃ වලදී "සුබ්හාන රබ්බියල්-අසීම්" සහ සජ්දාවේදී "සුබ්හාන රබ්බියල්-අඃලා" අවම වශයෙන් එක් වරක්  –  තුන් වරක් අවම සුන්නාව. 5) පළමු තශහ්හුද් (රකඅත් 3 හෝ 4ක සලාතයේදී). 6) අවසන් තශහ්හුදේදී නබි ﷺ වෙත සලවාත්. 7) සලාම් දෙකම. වාජිබයක් අමතක වුණොත් සලාතය වලංගුව පවතී; සලාම් වලට පෙර හෝ පසු අමතකවීමේ සජ්දා දෙකක් (සජ්දත් අස්-සහ්ව්) කරයි.` },

  uni_sunnah_h: { en: `Sunnah  –  recommended; abundant reward in performing them, no sin in omitting`, ms: `Sunnah  –  digalakkan; pahala besar bila dilakukan, tiada dosa bila ditinggalkan`, tur: `Sünnet  –  müstehab; yapana büyük sevap, terkinde günah yoktur`, urd: `سنّت  –  مستحب؛ ادا کرنے پر بڑا اجر، ترک پر گناہ نہیں`, ben: `সুন্নাহ  –  মুস্তাহাব; পালনে অপরিসীম সওয়াব, ছাড়লে গুনাহ নেই`, fas: `سنت  –  مستحب؛ پاداش فراوان در انجام، گناهی در ترک نیست`, zh: `圣行  –  受嘉许；行之大有回赐，遗之无罪`, yue: `聖行  –  受嘉許；行之大有回賜，遺之無罪`, ja: `スンナ  –  推奨；行えば大いなる報奨、省略しても罪はない`, ru: `Сунна  –  желательное; обильная награда за исполнение, нет греха за пропуск`, es: `Sunnah  –  recomendado; abundante recompensa al realizarlo, sin pecado al omitirlo`, ko: `순나  –  권장; 행하면 풍성한 보상, 빠뜨려도 죄가 아님`, ta: `சுன்னா  –  பரிந்துரைக்கப்பட்டது; செய்தால் அதிக நற்கூலி, விட்டாலும் பாவமில்லை`, si: `සුන්නා  –  නිර්දේශිත; ඉටු කළොත් මහත් කුසල්, අත්හැරියත් පාපයක් නැත` },
  uni_sunnah_body: { en: `1) Opening supplication (du'a al-istiftah)  –  most commonly "Subhanaka Allahumma...". 2) Saying "A'udhu billahi minash-shaytanir-rajim" and "Bismillah" silently before Fatihah in the first rak'ah. 3) Saying "Ameen" after Fatihah  –  aloud in audible prayers, silently in silent ones. 4) Lengthening the recitation in Fajr, medium length in Dhuhr and Asr, shorter in Maghrib, medium in Isha. 5) Looking at the place of sujud throughout the standing portions, and at the index finger during tashahhud. 6) Spreading the fingers in ruku' to grip the knees; keeping the back straight and parallel to the ground. 7) Reciting "Rabbighfir li" between the two prostrations. 8) Du'a in the final sujud and after the final tashahhud before the salam.`, ms: `1) Doa iftitah  –  yang paling masyhur "Subhanaka Allahumma...". 2) Membaca "A'udhu billahi minas-syaitanir-rajim" dan "Bismillah" secara perlahan sebelum Fatihah pada rakaat pertama. 3) Mengucap "Amin" selepas Fatihah  –  kuat pada solat jahriah, perlahan pada solat sirriah. 4) Memanjangkan bacaan dalam Subuh, sederhana dalam Zuhur dan Asar, lebih pendek dalam Maghrib, dan sederhana dalam Isyak. 5) Memandang ke tempat sujud sepanjang qiyam, dan ke jari telunjuk semasa tasyahhud. 6) Membuka jari-jari semasa rukuk untuk memegang lutut; mengekalkan belakang lurus selari dengan tanah. 7) Membaca "Rabbighfir li" antara dua sujud. 8) Doa pada sujud akhir dan selepas tasyahhud akhir sebelum salam.`, tur: `1) İftitah duası  –  en yaygını "Sübhâneke Allahümme...". 2) İlk rekâtta Fâtiha'dan önce sessizce "Eûzü billâhi mineşşeytânirracîm" ve "Bismillâh" demek. 3) Fâtiha'dan sonra "Âmîn" demek  –  cehrî namazlarda sesli, sirrî namazlarda sessiz. 4) Sabah'ta uzun, Öğle ve İkindi'de orta, Akşam'da kısa, Yatsı'da orta uzunlukta kıraat. 5) Kıyamda secde yerine, tahiyyâtta şehadet parmağına bakmak. 6) Rükûda parmakları açıp dizleri tutmak; sırtı düz ve yerle paralel tutmak. 7) İki secde arasında "Rabbiğfir lî" demek. 8) Son secdede ve son tahiyyât sonrası selamdan önce dua.`, urd: `(۱) دعائے استفتاح  –  مشہور "سبحانک اللھم..."۔ (۲) پہلی رکعت میں فاتحہ سے پہلے آہستہ "أعوذ باللہ من الشیطان الرجیم" اور "بسم اللہ" پڑھنا۔ (۳) فاتحہ کے بعد "آمین" کہنا  –  جہری نماز میں بلند، سری میں آہستہ۔ (۴) فجر میں طویل قراءت، ظہر و عصر میں متوسط، مغرب میں مختصر، عشاء میں متوسط۔ (۵) قیام میں سجدے کی جگہ پر اور تشہد میں شہادت کی انگلی پر نظر۔ (۶) رکوع میں انگلیاں کھول کر گھٹنوں کو پکڑنا؛ پیٹھ سیدھی اور زمین کے متوازی۔ (۷) دو سجدوں کے درمیان "رب اغفر لی"۔ (۸) آخری سجدے میں اور آخری تشہد کے بعد سلام سے قبل دعا۔`, ben: `১) দোয়ায়ে ইস্তিফতাহ  –  সর্বাধিক প্রচলিত "সুবহানাকা আল্লাহুম্মা..."। ২) প্রথম রাকাতে ফাতিহার আগে "আউযু বিল্লাহি মিনাশ-শাইতানির-রাজীম" ও "বিসমিল্লাহ" নীরবে পড়া। ৩) ফাতিহার পরে "আমীন" বলা  –  জোরে পড়ার নামাজে উচ্চস্বরে, নীরবের নামাজে নীরবে। ৪) ফজরে দীর্ঘ কেরাত, যোহর ও আসরে মাঝারি, মাগরিবে সংক্ষিপ্ত, ইশায় মাঝারি। ৫) দাঁড়ানো অবস্থায় সিজদার স্থানে এবং তাশাহহুদে শাহাদাত আঙুলের দিকে দৃষ্টি। ৬) রুকুতে আঙুল ফাঁক করে হাঁটু ধরা; পিঠ সোজা ও মাটির সমান্তরাল। ৭) দুই সিজদার মাঝে "রব্বিগফির লি"। ৮) শেষ সিজদায় এবং শেষ তাশাহহুদের পরে সালামের আগে দোয়া।`, fas: `۱) دعای استفتاح  –  مشهورترین "سبحانک اللهم...". ۲) خواندن آرامِ "أعوذ بالله من الشیطان الرجیم" و "بسم الله" پیش از فاتحه در رکعت اول. ۳) گفتن "آمین" پس از فاتحه  –  در نمازهای جهری بلند، در سرّی آرام. ۴) قرائت طولانی در فجر، متوسط در ظهر و عصر، کوتاه‌تر در مغرب، متوسط در عشاء. ۵) نگاه به جای سجده در قیام، و به انگشت شهادت در تشهد. ۶) باز کردن انگشتان در رکوع برای گرفتن زانوها؛ نگه داشتن پشت صاف و موازی زمین. ۷) "رب اغفر لی" میان دو سجده. ۸) دعا در سجده آخر و پس از تشهد آخر پیش از سلام.`, zh: `(一)开经祈祷（祈祷启）  –  最常见为「Subhanaka Allahumma…」。(二)首拜中在《开端章》前低声诵「我求护于真主免遭被驱逐的恶魔」与「奉真主之名」。(三)《开端章》后念「阿敏」  –  应高声之拜中高声，应默念之拜中低声。(四)晨礼诵长经，晌礼与晡礼中等，昏礼较短，宵礼中等。(五)立时凝视叩头之处，作证时凝视食指。(六)鞠躬时张开手指握住膝盖；背部挺直与地面平行。(七)两次叩头之间念「我的主啊，请赦免我」。(八)末次叩头中及末次作证后、平安词前作祈祷。`, yue: `(一)開經祈禱（祈禱啟）  –  最常見為「Subhanaka Allahumma…」。(二)首拜中喺《開端章》前低聲誦「我求護於真主免遭被驅逐嘅惡魔」與「奉真主之名」。(三)《開端章》後念「阿敏」  –  應高聲之拜中高聲，應默念之拜中低聲。(四)晨禮誦長經，晌禮與晡禮中等，昏禮較短，宵禮中等。(五)立時凝視叩頭之處，作證時凝視食指。(六)鞠躬時張開手指握住膝蓋；背部挺直與地面平行。(七)兩次叩頭之間念「我的主啊，請赦免我」。(八)末次叩頭中及末次作證後、平安詞前作祈禱。`, ja: `(1) 開始の祈願（ドゥア・アル＝イスティフターハ）  –  最も一般的なのは「スブハーナカ・アッラーフマ…」。(2) 第一ラクアでファーティハの前に「アウーズ・ビッラーヒ・ミナッシャイターニル＝ラジーム」と「ビスミッラー」を密かに唱える。(3) ファーティハの後に「アーミーン」を唱える  –  音読の礼拝では声に出し、無音の礼拝では密かに。(4) ファジュルで長く、ズフルとアスルで中程度、マグリブで短く、イシャーで中程度の朗誦。(5) 立位中はスジュードの場所を、タシャフードの間は人差し指を見る。(6) ルクー時は指を広げて膝を掴み、背を真っ直ぐ地面と平行に保つ。(7) 二度の平伏の間に「ラッビグフィル・リー」と唱える。(8) 最後のスジュードでと、最後のタシャフード後サラームの前にドゥア。`, ru: `1) Открывающая мольба (ду'а аль-истифтах)  –  чаще всего "Субханака Аллахумма...". 2) Произнесение "А'узу биллахи мина-ш-шайтани-р-раджим" и "Бисмиллах" про себя перед Фатихой в первом ракате. 3) Произнесение "Амин" после Фатихи  –  вслух в громких молитвах, про себя в тихих. 4) Удлинение чтения в Фаджре, средней длины в Зухре и Асре, короче в Магрибе, средней длины в Иша. 5) Взгляд на место суджуда во время стояния и на указательный палец во время ташаххуда. 6) Расставление пальцев в руку' для обхвата колен; спина прямая и параллельна земле. 7) "Рабби-гфир ли" между двумя суджудами. 8) Дуа в последнем суджуде и после последнего ташаххуда перед саламом.`, es: `1) Súplica de apertura (du'a al-istiftah)  –  la más común "Subhanaka Allahumma...". 2) Decir "A'udhu billahi minash-shaytanir-rajim" y "Bismillah" en voz baja antes de la Fatiha en el primer rak'ah. 3) Decir "Ameen" tras la Fatiha  –  en voz alta en oraciones audibles, en silencio en las silenciosas. 4) Alargar la recitación en Fajr, longitud media en Dhuhr y Asr, más breve en Maghrib, media en Isha. 5) Mirar el lugar del sujud durante las partes de pie y al índice durante el tashahhud. 6) Separar los dedos en ruku' para asir las rodillas; mantener la espalda recta y paralela al suelo. 7) Recitar "Rabbighfir li" entre las dos prosternaciones. 8) Du'a en el sujud final y tras el tashahhud final antes del salam.`, ko: `1) 시작의 기원(두아 알이스티프타하)  –  가장 일반적으로 "수브하나카 알라훔마…". 2) 첫 라카에서 파티하 전에 "아우두 빌라히 미나샤이타닐 라짐"과 "비스밀라"를 조용히 말함. 3) 파티하 후에 "아민" 말하기  –  소리 내는 예배에서는 소리 내어, 조용한 예배에서는 조용히. 4) 파즈르에서 길게, 주흐르와 아스르에서 중간, 마그립에서 짧게, 이샤에서 중간 길이로 낭송. 5) 서 있는 동안에는 수주드 자리를, 타샤후드 중에는 검지손가락을 응시. 6) 루쿠으에서 손가락을 벌려 무릎을 잡고, 등을 곧고 바닥과 평행하게 유지. 7) 두 엎드림 사이에 "랍비그피르 리". 8) 마지막 수주드와 마지막 타샤후드 후 살람 전에 두아.`, ta: `1) தொடக்க துஆ (துஆ அல்-இஸ்திஃப்தாஹ்)  –  மிகவும் பொதுவானது "ஸுப்ஹானக அல்லாஹும்ம...". 2) முதல் ரக்அத்தில் ஃபாதிஹாவுக்கு முன் "அஊது பில்லாஹி மினஷ்-ஷைதானிர்-ரஜீம்" மற்றும் "பிஸ்மில்லாஹ்" அமைதியாக ஓதுதல். 3) ஃபாதிஹாவுக்குப் பின் "ஆமீன்" சொல்லுதல்  –  ஜஹ்ரியான தொழுகைகளில் சத்தமாக, ஸிர்ரியான தொழுகைகளில் அமைதியாக. 4) ஃபஜ்ரில் நீண்ட ஓதல், ளுஹர் மற்றும் அஸ்ரில் நடுத்தர, மக்ரிபில் குறுகியது, இஷாவில் நடுத்தரம். 5) நிற்கையில் சுஜூத் இடத்தையும், தஷஹ்ஹுதின்போது ஆட்காட்டி விரலையும் பார்த்தல். 6) ருகூஉவில் விரல்களை விரித்து முழங்கால்களைப் பிடித்தல்; முதுகை நேராக, தரைக்கு இணையாக வைத்தல். 7) இரு சுஜூதுகளுக்கு இடையே "ரப்பிக்ஃபிர் லீ". 8) இறுதி சுஜூதில் மற்றும் இறுதி தஷஹ்ஹுதுக்குப் பின் ஸலாமுக்கு முன் துஆ.`, si: `1) ආරම්භක ප්‍රාර්ථනය (දුආ අල්-ඉස්තිෆ්තාහා)  –  වඩාත් සුලභව "සුබ්හානක අල්ලාහුම්ම...". 2) පළමු රකඅතේ ෆාතිහා පෙර "අඃ-උදු බිල්ලාහි මිනෂ්-ෂෛතානිර්-රජීම්" සහ "බිස්මිල්ලාහ්" නිහඬව කීම. 3) ෆාතිහා පසු "ආමීන්" කීම  –  හඬ ඇති සලාතවල හඬ නඟා, නිහඬ සලාතවල නිහඬව. 4) ෆජ්ර්හි දිගු කියවීම, ලුහර් හා අස්ර්හි මධ්‍යම, මග්රිබ්හි කෙටි, ඉෂාහි මධ්‍යම. 5) සිටගෙන සිටින අවස්ථාවලදී සජ්දා ස්ථානය දෙසත්, තශහ්හුද් අතරතුර අතගත ඇඟිල්ල දෙසත් බැලීම. 6) රුකූඃවේදී ඇඟිලි විදහා දන හිස් අල්ලාගනීම; පිට කෙළින් හා බිමට සමාන්තරව තබාගැනීම. 7) සජ්දා දෙක අතර "රබ්බිග්ෆිර් ලී". 8) අවසන් සජ්දාවේදී සහ අවසන් තශහ්හුද් පසු සලාම් වලට පෙර දුආ.` },

  uni_extras_h: { en: `Extras  –  added rewards from established Sunnah`, ms: `Tambahan  –  pahala bonus daripada Sunnah yang sabit`, tur: `Ekstralar  –  sabit sünnetten ek sevaplar`, urd: `اضافی اعمال  –  ثابت سنّت سے زائد اجر`, ben: `অতিরিক্ত  –  সাব্যস্ত সুন্নাহ থেকে অতিরিক্ত সওয়াব`, fas: `موارد اضافی  –  پاداش‌های افزون از سنت ثابت`, zh: `附加  –  从确证圣行中获得的额外回赐`, yue: `附加  –  從確證聖行中獲得嘅額外回賜`, ja: `追加事項  –  確立されたスンナによる追加の報奨`, ru: `Дополнительные  –  добавочные награды из установленной Сунны`, es: `Extras  –  recompensas añadidas de la Sunnah establecida`, ko: `추가 행위  –  확립된 순나로부터의 추가 보상`, ta: `கூடுதல்கள்  –  நிறுவப்பட்ட சுன்னாவின் கூடுதல் கூலி`, si: `අමතර  –  ස්ථාපිත සුන්නාවෙන් අමතර කුසල්` },
  uni_extras_body: { en: `1) After the closing salam: three times "Astaghfirullah", then "Allahumma antas-salam wa minkas-salam tabarakta ya dhal-jalali wal-ikram". 2) "La ilaha illallahu wahdahu la sharika lahu...". 3) Tasbih, tahmid and takbir 33-33-34 times (Subhanallah, Alhamdulillah, Allahu Akbar). 4) Recitation of Ayat al-Kursi (2:255), Surah al-Ikhlas, al-Falaq and an-Nas after each fard prayer. 5) Du'a in one's own words at the end of each prayer  –  the Prophet ﷺ said "between the call to prayer and the iqamah, du'a is not rejected." 6) For Fajr and Maghrib specifically: ten times the testimony of faith with "lahul-mulku wa lahul-hamd...". The Prophet ﷺ said whoever does this is granted enormous reward and protection from Shaytan until evening.`, ms: `1) Selepas salam: tiga kali "Astaghfirullah", kemudian "Allahumma antas-salam wa minkas-salam tabarakta ya dhal-jalali wal-ikram". 2) "La ilaha illallahu wahdahu la sharika lahu...". 3) Tasbih, tahmid, dan takbir 33-33-34 kali (Subhanallah, Alhamdulillah, Allahu Akbar). 4) Membaca Ayat al-Kursi (2:255), Surah al-Ikhlas, al-Falaq dan an-Nas selepas setiap solat fardu. 5) Doa dengan kata-kata sendiri pada akhir setiap solat  –  Nabi ﷺ bersabda "antara azan dan iqamah, doa tidak ditolak". 6) Khusus Subuh dan Maghrib: sepuluh kali kalimah syahadah dengan "lahul-mulku wa lahul-hamd...". Nabi ﷺ bersabda sesiapa yang melakukannya diberi pahala besar dan perlindungan daripada Syaitan sehingga petang.`, tur: `1) Selamdan sonra: üç kez "Estağfirullah", ardından "Allahümme entes-selâm ve minkes-selâm tebârakte yâ zel-celâli vel-ikrâm". 2) "Lâ ilâhe illallâhu vahdehû lâ şerîke leh...". 3) Tesbih, tahmid ve tekbir 33-33-34 (Sübhânallah, Elhamdülillâh, Allahu Ekber). 4) Her farz namazdan sonra Âyetü'l-Kürsî (2:255), İhlâs, Felak ve Nâs surelerini okumak. 5) Her namazın sonunda kendi sözleriyle dua  –  Peygamber ﷺ "Ezan ile kâmet arasında yapılan dua reddedilmez." buyurdu. 6) Özellikle Sabah ve Akşam'da: on kez kelime-i şehadeti "lehül-mülkü ve lehül-hamd..." ile söylemek. Peygamber ﷺ bunu yapan kişiye büyük sevap ve akşama kadar şeytandan korunma vaad etmiştir.`, urd: `(۱) سلام کے بعد: تین بار "أستغفر اللہ"، پھر "اللہم انت السلام ومنک السلام تبارکت یا ذا الجلال والإکرام"۔ (۲) "لا إلہ إلا اللہ وحدہ لا شریک لہ..."۔ (۳) تسبیح، تحمید اور تکبیر ۳۳-۳۳-۳۴ بار (سبحان اللہ، الحمد للہ، اللہ اکبر)۔ (۴) ہر فرض کے بعد آیت الکرسی (۲:۲۵۵)، سورۃ الاخلاص، الفلق اور الناس پڑھنا۔ (۵) ہر نماز کے آخر میں اپنی زبان میں دعا  –  نبی ﷺ نے فرمایا "اذان اور اقامت کے درمیان دعا رد نہیں ہوتی"۔ (۶) خاص طور پر فجر و مغرب کے بعد: دس مرتبہ کلمہ شہادت "لہ الملک ولہ الحمد..." کے ساتھ۔ نبی ﷺ نے فرمایا یہ کرنے والے کو بڑا اجر اور شام تک شیطان سے حفاظت ملتی ہے۔`, ben: `১) সালামের পর: তিনবার "আস্তাগফিরুল্লাহ", তারপর "আল্লাহুম্মা আনতাস-সালাম ওয়া মিনকাস-সালাম তাবারাকতা ইয়া যাল-জালালি ওয়াল-ইকরাম"। ২) "লা ইলাহা ইল্লাল্লাহু ওয়াহদাহু লা শরীকা লাহু..."। ৩) তাসবিহ, তাহমিদ ও তাকবির ৩৩-৩৩-৩৪ বার (সুবহানাল্লাহ, আলহামদুলিল্লাহ, আল্লাহু আকবার)। ৪) প্রতি ফরজ নামাজের পর আয়াতুল কুরসী (২:২৫৫), সূরা ইখলাস, ফালাক ও নাস পড়া। ৫) প্রতি নামাজের শেষে নিজের ভাষায় দোয়া  –  নবী ﷺ বলেছেন "আযান ও ইকামতের মাঝে দোয়া প্রত্যাখ্যাত হয় না"। ৬) বিশেষত ফজর ও মাগরিবে: দশবার শাহাদাতের কালেমা "লাহুল-মুলকু ওয়া লাহুল-হামদ..." সহ। নবী ﷺ বলেছেন যে এটি করে তাকে বিরাট সওয়াব ও সন্ধ্যা পর্যন্ত শয়তান থেকে সুরক্ষা দেওয়া হয়।`, fas: `۱) پس از سلام: سه بار "أستغفر الله"، سپس "اللهم أنت السلام و منک السلام تبارکت یا ذا الجلال و الإکرام". ۲) "لا إله إلا الله وحده لا شریک له...". ۳) تسبیح، تحمید و تکبیر ۳۳-۳۳-۳۴ بار (سبحان الله، الحمد لله، الله أکبر). ۴) خواندن آیة الکرسی (۲:۲۵۵)، سوره اخلاص، فلق و ناس پس از هر نماز فرض. ۵) دعا با کلمات خود در پایان هر نماز  –  پیامبر ﷺ فرمود "میان اذان و اقامه، دعا رد نمی‌شود". ۶) به‌ویژه پس از فجر و مغرب: ده بار شهادتین با "له الملک و له الحمد...". پیامبر ﷺ فرمود انجام‌دهنده آن، پاداش بزرگ و حفاظت از شیطان تا شب می‌یابد.`, zh: `(一)平安词后：三遍「我向真主求恕」（Astaghfirullah），随后「Allahumma antas-salam wa minkas-salam tabarakta ya dhal-jalali wal-ikram」。(二)「La ilaha illallahu wahdahu la sharika lahu…」。(三)赞美词、感赞词、大赞词各33-33-34遍（Subhanallah、Alhamdulillah、Allahu Akbar）。(四)每次主命拜后诵《宝座经》（2:255）、忠诚章、黎明章与世人章。(五)每次拜功末以自己的话祈祷  –  先知ﷺ言「宣礼与起立之间的祈祷不被拒绝」。(六)特别于晨礼与昏礼：十遍作证词配「lahul-mulku wa lahul-hamd…」。先知ﷺ言行此者获巨大回赐，至晚间得护免恶魔。`, yue: `(一)平安詞後：三遍「我向真主求恕」（Astaghfirullah），隨後「Allahumma antas-salam wa minkas-salam tabarakta ya dhal-jalali wal-ikram」。(二)「La ilaha illallahu wahdahu la sharika lahu…」。(三)讚美詞、感讚詞、大讚詞各33-33-34遍（Subhanallah、Alhamdulillah、Allahu Akbar）。(四)每次主命拜後誦《寶座經》（2:255）、忠誠章、黎明章與世人章。(五)每次拜功末以自己嘅話祈禱  –  先知ﷺ言「宣禮與起立之間嘅祈禱不被拒絕」。(六)特別於晨禮與昏禮：十遍作證詞配「lahul-mulku wa lahul-hamd…」。先知ﷺ言行此者獲巨大回賜，至夜間得護免惡魔。`, ja: `(1) サラーム後に：三度「アスタグフィルッラー」、続いて「アッラーフマ・アンタッ＝サラーム・ワ・ミンカッ＝サラーム・タバーラクタ・ヤー・ザル＝ジャラーリ・ワル＝イクラーム」。(2)「ラー・イラーハ・イッラッラーフ・ワフダフー・ラー・シャリーカ・ラフー…」。(3) タスビーフ、タハミード、タクビールを33-33-34回（スブハーナッラー、アルハムドゥリッラー、アッラーフ・アクバル）。(4) 各ファルド礼拝後にアーヤトゥル＝クルスィー（2:255）、イフラース章、ファラク章、ナース章を朗誦。(5) 各礼拝の終わりに自分の言葉でドゥア  –  預言者ﷺは「アザーンとイカーマの間のドゥアは却下されない」と仰せられた。(6) 特にファジュルとマグリブの後に：信仰告白を十度、「ラフル＝ムルク・ワ・ラフル＝ハムド…」とともに。預言者ﷺは行う者に大いなる報奨と夕方までのシャイターンからの守護を約束された。`, ru: `1) После завершающего салама: трижды "Астагфируллах", затем "Аллахумма антас-салям ва минкас-салям табаракта йа заль-джаляли валь-икрам". 2) "Ля иляха илляллаху вахдаху ля шарика лаху...". 3) Тасбих, тахмид и такбир по 33-33-34 (Субханаллах, Альхамдулиллях, Аллаху Акбар). 4) Чтение Аят аль-Курси (2:255), сур аль-Ихляс, аль-Фаляк и ан-Нас после каждой обязательной молитвы. 5) Дуа своими словами в конце каждой молитвы  –  Пророк ﷺ сказал "между азаном и икамой дуа не отвергается". 6) В частности после Фаджра и Магриба: десять раз свидетельство веры с "ляхуль-мульку ва ляхуль-хамд...". Пророк ﷺ сказал, что совершающему это дарована огромная награда и защита от шайтана до вечера.`, es: `1) Tras el salam final: tres veces "Astaghfirullah", luego "Allahumma antas-salam wa minkas-salam tabarakta ya dhal-jalali wal-ikram". 2) "La ilaha illallahu wahdahu la sharika lahu...". 3) Tasbih, tahmid y takbir 33-33-34 veces (Subhanallah, Alhamdulillah, Allahu Akbar). 4) Recitación de Ayat al-Kursi (2:255), Sura al-Ikhlas, al-Falaq y an-Nas tras cada oración obligatoria. 5) Du'a con palabras propias al final de cada oración  –  el Profeta ﷺ dijo "entre el adhan y la iqamah, el du'a no es rechazado". 6) Especialmente tras Fajr y Maghrib: diez veces el testimonio de fe con "lahul-mulku wa lahul-hamd...". El Profeta ﷺ dijo que a quien lo hace se le otorga enorme recompensa y protección de Shaytan hasta el atardecer.`, ko: `1) 마치는 살람 후: 세 번 "아스타그피룰라", 이어 "알라훔마 안타살람 와 민카살람 타바라크타 야 잘잘랄리 왈이크람". 2) "라 일라하 일랄라후 와흐다후 라 샤리카 라후…". 3) 타스비흐, 타흐미드, 타크비르 각 33-33-34회(수브하날라, 알함둘릴라, 알라후 아크바르). 4) 각 의무 예배 후 아야툴 쿠르시(2:255), 알이클라스, 알팔라크, 안나스 장 낭송. 5) 각 예배 끝에 자신의 말로 두아  –  예언자 ﷺ께서 "아잔과 이까마 사이의 두아는 거절되지 않는다"고 말씀하셨다. 6) 특히 파즈르와 마그립 후에: 열 번의 신앙 증언과 함께 "라훌물쿠 와 라훌함드…". 예언자 ﷺ께서는 이를 행하는 자에게 거대한 보상과 저녁까지 사탄으로부터의 보호가 있다고 하셨다.`, ta: `1) முடிவுச் ஸலாமுக்குப் பின்: மூன்று முறை "அஸ்தக்ஃபிருல்லாஹ்", பின் "அல்லாஹும்ம அன்தஸ்-ஸலாம் வ மின்கஸ்-ஸலாம் தபாரக்த யா தல்-ஜலாலி வல்-இக்ராம்". 2) "லா இலாஹ இல்லல்லாஹு வஹ்தஹு லா ஷரீக லஹு...". 3) தஸ்பீஹ், தஹ்மீத், தக்பீர் 33-33-34 முறை (ஸுப்ஹானல்லாஹ், அல்ஹம்துலில்லாஹ், அல்லாஹு அக்பர்). 4) ஒவ்வொரு ஃபர்ள் தொழுகைக்குப் பின் ஆயத்துல் குர்ஸி (2:255), சூரத்துல் இக்லாஸ், அல்-ஃபலக் மற்றும் அந்-நாஸ் ஓதுதல். 5) ஒவ்வொரு தொழுகையின் முடிவில் தம் சொற்களில் துஆ  –  நபி ﷺ "அதானுக்கும் இகாமத்துக்கும் இடையே துஆ நிராகரிக்கப்படாது" எனக் கூறினார். 6) குறிப்பாக ஃபஜ்ர் மற்றும் மக்ரிபுக்குப் பின்: பத்து முறை சாட்சியக் கலிமா "லஹுல்-முல்கு வ லஹுல்-ஹம்த்..." உடன். நபி ﷺ இதைச் செய்பவருக்குப் பெரும் கூலியும், மாலை வரை ஷைத்தானிடமிருந்து பாதுகாப்பும் உள்ளது எனக் கூறினார்.`, si: `1) අවසන් සලාම් පසු: තෙවරක් "අස්තග්ෆිරුල්ලාහ්", පසුව "අල්ලාහුම්ම අන්තස්-සලාම් ව මින්කස්-සලාම් තබාරක්ත යා දල්-ජලාලි වල්-ඉක්රාම්". 2) "ලා ඉලාහ ඉල්ලල්ලාහු වහ්දහු ලා ෂරීක ලහු...". 3) තස්බීහ්, තහ්මීද්, තක්බීර් 33-33-34 වරක් (සුබ්හානල්ලාහ්, අල්හම්දුලිල්ලාහ්, අල්ලාහු අක්බර්). 4) සෑම ෆර්ද් සලාතයකට පසු ආයතුල් කුර්සී (2:255), අල්-ඉක්ලාස් සූරාව, අල්-ෆලක් සහ අන්-නාස් කියවීම. 5) සෑම සලාතයක අවසානයේ තමන්ගේ වචනවලින් දුආ  –  නබි ﷺ "අදාන් සහ ඉකාමා අතර දුආ ප්‍රතික්ෂේප නොවේ" යැයි පැවසූහ. 6) විශේෂයෙන් ෆජ්ර් සහ මග්රිබ් පසු: දස වරක් ශහාදතය "ලහුල්-මුල්කු ව ලහුල්-හම්ද්..." සමඟ. නබි ﷺ එය කරන්නාට මහත් කුසල් සහ සවස් වන තෙක් ෂෛතාන්ගෙන් ආරක්ෂාව ලැබෙන බව පැවසූහ.` },
  /* ── Fajr ─────────────────────────────────────────────────── */
  fajr_name: { en: `Fajr  –  The Dawn Prayer`, ms: `Fajar (Subuh)  –  Solat Waktu Subuh`, tur: `Sabah Namazı  –  Fecr`, urd: `فجر  –  صبح کی نماز`, ben: `ফজর  –  ভোরের নামাজ`, fas: `فجر  –  نماز سپیده‌دم`, zh: `晨礼  –  破晓拜功`, yue: `晨禮  –  破曉拜功`, ja: `ファジュル  –  夜明けの礼拝`, ru: `Фаджр  –  предрассветная молитва`, es: `Fajr  –  la oración del alba`, ko: `파즈르  –  새벽 예배`, ta: `ஃபஜ்ர்  –  விடியல் தொழுகை`, si: `ෆජ්ර්  –  උදෑසන සලාතය` },
  fajr_when: { en: `Begins at true dawn (al-fajr al-sadiq), the moment the horizontal white light first spreads across the eastern horizon, and ends at sunrise. Performed before the sun's disc appears. It is the only daily prayer prayed while it is still dark, marking the transition from night to day.`, ms: `Bermula pada fajar sadiq (cahaya putih melintang di ufuk timur) dan berakhir ketika matahari terbit. Dilakukan sebelum cakra matahari muncul. Ini satu-satunya solat fardu yang ditunaikan ketika masih gelap, menandakan peralihan daripada malam kepada siang.`, tur: `Fecr-i sâdıkta (gerçek tan yerinde beyaz aydınlığın doğu ufkunda yatay olarak yayıldığı an) başlar ve güneşin doğuşuna kadar sürer. Güneş diski görünmeden kılınır. Hâlâ karanlıkken kılınan tek farz namazdır; geceden gündüze geçişi simgeler.`, urd: `صبحِ صادق (افق مشرق پر سفید روشنی کا افقی پھیلنا) سے شروع ہو کر طلوعِ آفتاب پر ختم۔ سورج کا قرص ظاہر ہونے سے پہلے ادا کی جاتی ہے۔ یہ واحد فرض نماز ہے جو اندھیرے میں ادا ہوتی ہے، رات سے دن کی منتقلی کی علامت۔`, ben: `সত্য ভোর (আল-ফাজর আস-সাদিক  –  পূর্ব আকাশে আনুভূমিক সাদা আলোর প্রথম বিস্তার) থেকে শুরু হয়ে সূর্যোদয়ে শেষ। সূর্যের চাকতি দেখা যাওয়ার আগেই আদায় করা হয়। এটিই একমাত্র ফরজ নামাজ যা অন্ধকারে আদায় করা হয়, রাত থেকে দিনের পরিবর্তনের প্রতীক।`, fas: `از فجر صادق (نخستین گستردگی روشنایی سفید افقی در افق شرقی) آغاز و تا طلوع خورشید ادامه دارد. پیش از پدیدار شدن قرص خورشید گزارده می‌شود. تنها نماز فرض روزانه است که در تاریکی خوانده می‌شود و نشانه گذار از شب به روز است.`, zh: `自真黎明（破晓白光于东方地平线横向铺开之时）开始，至日出结束。须在日轮出现之前完成。这是唯一在黑暗中完成的主命拜功，标志着夜与昼的交替。`, yue: `由真黎明（破曉白光於東方地平線橫向鋪開之時）開始，至日出結束。須喺日輪出現之前完成。呢個係唯一喺黑暗中完成嘅主命拜功，標誌住夜同晝嘅交替。`, ja: `真の夜明け（ファジュル・サーディク：白い光が東の地平線に横一文字に広がる瞬間）から始まり、日の出で終わる。太陽の円盤が現れる前に行う。まだ暗いうちに行う唯一の毎日のファルド礼拝で、夜から昼への移り変わりを印す。`, ru: `Начинается с истинного рассвета (аль-фаджр ас-садик) — мгновения, когда белый горизонтальный свет впервые расходится по восточному горизонту, и заканчивается восходом солнца. Совершается до появления диска солнца. Это единственная ежедневная молитва, совершаемая в темноте, отмечающая переход от ночи к дню.`, es: `Comienza con el verdadero amanecer (al-fajr al-sadiq), el instante en que la luz blanca horizontal se extiende por primera vez sobre el horizonte oriental, y termina al amanecer. Se realiza antes de que aparezca el disco solar. Es la única oración diaria que se reza aún de noche, marcando la transición de la noche al día.`, ko: `참 새벽(알파즈르 알사디크) — 흰 빛이 동쪽 지평선에 가로로 처음 펼쳐지는 순간 — 에 시작되어 일출에 끝납니다. 태양 원반이 나타나기 전에 행합니다. 어둠 속에서 행하는 유일한 의무 일일 예배로, 밤에서 낮으로의 전환을 표시합니다.`, ta: `உண்மை விடியல் (அல்-ஃபஜ்ர் அஸ்-ஸாதிக் — கீழ்த்திசை வானத்தில் வெள்ளை வெளிச்சம் கிடைமட்டமாக முதலில் பரவும் தருணம்) தொடங்கி சூரிய உதயத்தில் முடிகிறது. சூரிய வட்டு தோன்றுவதற்கு முன் தொழப்படுகிறது. இருளில் தொழப்படும் ஒரே தினசரி கடமைத் தொழுகை இது, இரவிலிருந்து பகலுக்கு மாறுவதைக் குறிக்கிறது.`, si: `සැබෑ අරුණෝදය (අල්-ෆජ්ර් අස්-සාදිඃක්  –  සුදු ආලෝකය නැගෙනහිර ක්ෂිතිජයේ තිරස් ලෙස පළමුවරට පැතිර යන මොහොත) සිට ආරම්භ වී හිරු උදාවේදී අවසන් වේ. හිරුගේ තැටිය පෙනීමට පෙර ඉටු කරයි. තවමත් අඳුර ඇති අතරතුර ඉටු කරන එකම අනිවාර්ය දෛනික සලාතය වන අතර, රාත්‍රියේ සිට දවලට මාරුවීම සලකුණු කරයි.` },
  fajr_structure: { en: `Two rak'ahs of fard. Preceded by two rak'ahs of confirmed Sunnah (Sunnah al-Fajr), which the Prophet ﷺ never abandoned at home or on journey, calling it "better than the world and all it contains." Recitation is aloud (jahri) for both rak'ahs.`, ms: `Dua rakaat fardu. Didahului oleh dua rakaat sunat muakkad (Sunnah al-Fajr), yang Nabi ﷺ tidak pernah meninggalkannya di rumah atau dalam musafir, dan baginda bersabda ia "lebih baik daripada dunia dan segala isinya". Bacaan dengan suara kuat (jahri) untuk kedua-dua rakaat.`, tur: `İki rekât farz. Öncesinde, Peygamber'in ﷺ ne evde ne seferde terk etmediği iki rekât müekked sünnet vardır; bunun için "dünyadan ve içindekilerden daha hayırlıdır" buyurmuştur. Her iki rekâtta da kıraat cehrî (sesli) yapılır.`, urd: `دو رکعت فرض۔ اس سے قبل دو رکعت سنّتِ مؤکدہ (سنّت الفجر) ہیں جنہیں نبی ﷺ نے گھر یا سفر میں کبھی نہیں چھوڑا اور فرمایا یہ "دنیا اور اس میں جو کچھ ہے، اس سے بہتر" ہیں۔ دونوں رکعات میں قراءت جہراً (بلند) ہوتی ہے۔`, ben: `দুই রাকাত ফরজ। এর আগে দুই রাকাত সুন্নাহ মুআক্কাদা (সুন্নাহ আল-ফজর), যা নবী ﷺ ঘরে বা সফরে কখনো ছাড়েননি, বলেছেন তা "দুনিয়া ও তার মধ্যে যা আছে সবকিছুর চেয়ে উত্তম"। উভয় রাকাতেই উচ্চস্বরে (জাহরি) কেরাত।`, fas: `دو رکعت فرض. پیش از آن دو رکعت سنت مؤکد (سنت فجر) که پیامبر ﷺ هرگز در حضر یا سفر آن را ترک نکرد و فرمود "از دنیا و آنچه در آن است بهتر" است. قرائت در هر دو رکعت با صدای بلند (جهری) است.`, zh: `主命两拜。前有两拜确证圣行（晨礼前圣行），先知ﷺ无论在家或旅行皆未曾舍弃，并称其"胜过世界与其中一切"。两拜均高声诵读（贾赫里）。`, yue: `主命兩拜。前有兩拜確證聖行（晨禮前聖行），先知ﷺ無論喺屋企或旅行都未曾捨棄過，並稱其「勝過世界與其中一切」。兩拜均高聲誦讀（賈赫里）。`, ja: `ファルドは二ラクア。その前に二ラクアの確認されたスンナ（スンナ・アル＝ファジュル）があり、預言者ﷺは在宅でも旅でもこれを欠かさず、「世界とその中にあるすべてより善い」と言われた。両ラクアとも声に出して（ジャフリー）朗誦する。`, ru: `Два раката фарда. Им предшествуют два раката подтверждённой сунны (Сунна аль-Фаджр), которые Пророк ﷺ не оставлял ни дома, ни в пути, называя их «лучше мира и всего, что в нём». Чтение вслух (джахрий) в обоих ракатах.`, es: `Dos rak'ahs de fard. Precedida por dos rak'ahs de Sunnah confirmada (Sunnah al-Fajr), que el Profeta ﷺ nunca abandonó ni en casa ni de viaje, llamándola "mejor que el mundo y cuanto contiene". La recitación es en voz alta (jahri) en ambos rak'ahs.`, ko: `파르드 두 라카. 앞서 두 라카의 확인된 순나(순나 알파즈르)가 있으며, 예언자 ﷺ께서는 집에서도 여행 중에도 결코 거르지 않으셨고 이를 "세상과 그 안의 모든 것보다 낫다"고 말씀하셨습니다. 두 라카 모두 소리 내어(자흐리) 낭송합니다.`, ta: `இரண்டு ரக்அத் ஃபர்ள். அதற்கு முன் இரண்டு ரக்அத் சுன்னத்துல் முஅக்கதா (சுன்னத் அல்-ஃபஜ்ர்), நபி ﷺ வீட்டிலும் பயணத்திலும் ஒருபோதும் கைவிடாமல் "உலகத்தையும் அதிலுள்ள அனைத்தையும் விட சிறந்தது" எனக் கூறியது. இரு ரக்அத்களிலும் உரக்க (ஜஹ்ரி) ஓதப்படுகிறது.`, si: `ෆර්ද් රකඅත් දෙකකි. ඊට පෙර තහවුරු කළ සුන්නා රකඅත් දෙකක් (සුන්නා අල්-ෆජ්ර්) ඇත; නබි ﷺ එය නිවසේදී හෝ ගමනකදී කිසිවිටෙක අත් නොහැරිය අතර, එය "ලෝකයටත් එහි ඇති සියල්ලටත් වඩා යහපත්" යැයි පැවසූහ. රකඅත් දෙකේදීම හඬ නඟා (ජහ්රී) කියවයි.` },
  fajr_story: { en: `Like all five prayers, Fajr was ordained on the Night Journey when the Prophet ﷺ ascended through the seven heavens and Allah originally prescribed fifty daily prayers, eventually reduced to five (with the reward of fifty). Specifically about Fajr, Jibril (as) led the Prophet ﷺ in this prayer at the Ka'bah twice on consecutive days to teach its time: once at the very beginning of dawn and once just before sunrise, then said: "The time is between these two."`, ms: `Seperti semua lima solat, Fajar diwajibkan pada malam Isra' dan Mi'raj ketika Nabi ﷺ naik ke tujuh langit dan Allah mulanya mewajibkan lima puluh solat sehari, akhirnya dikurangkan kepada lima (dengan ganjaran lima puluh). Khusus tentang Fajar, Jibril (as) mengimamkan Nabi ﷺ pada solat ini di Kaabah dua kali pada hari berturut-turut untuk mengajar waktunya: sekali pada permulaan fajar dan sekali sebelum matahari terbit, kemudian berkata: "Waktunya antara kedua-dua ini."`, tur: `Beş vakit gibi Sabah namazı da Mi'rac gecesinde, Peygamber ﷺ yedi göğe yükseldiğinde farz kılındı. Allah önce günde elli vakit emretti, sonunda beşe indirildi (ödülü elli). Sabah özelinde, Cibril (as) Peygamber'e ﷺ Kâbe yanında iki gün arka arkaya bu namazı kıldırarak vaktini öğretti: bir kez tan yerinin tam başında, bir kez güneş doğmadan az önce, sonra dedi: "Vakit bu ikisinin arasıdır."`, urd: `پانچوں نمازوں کی طرح فجر بھی شبِ معراج میں واجب ہوئی جب نبی ﷺ ساتوں آسمانوں پر تشریف لے گئے اور اللہ نے ابتدائی طور پر یومیہ پچاس نمازیں فرض کیں، آخرکار پانچ ہو گئیں (پچاس کے اجر کے ساتھ)۔ فجر کے بارے میں خاص بات: جبریل (ع) نے کعبہ کے پاس دو روز پے در پے نبی ﷺ کو یہ نماز پڑھائی تاکہ وقت سکھائیں: ایک بار طلوعِ فجر کے آغاز پر اور ایک بار طلوعِ آفتاب سے کچھ پہلے، پھر فرمایا: "وقت ان دونوں کے درمیان ہے۔"`, ben: `পাঁচ ওয়াক্ত নামাজের মতোই ফজরও মেরাজের রাতে ফরজ হয়, যখন নবী ﷺ সাত আসমানে উন্নীত হন; আল্লাহ প্রথমে দৈনিক পঞ্চাশ নামাজ ফরজ করেছিলেন, যা শেষ পর্যন্ত পাঁচে নামিয়ে আনা হয় (পঞ্চাশের সওয়াবসহ)। বিশেষত ফজর সম্পর্কে: জিবরিল (আ) নবী ﷺ-কে কাবার পাশে পরপর দুই দিনে এই নামাজে ইমামতি করেন সময় শেখাতে: একবার ভোরের একদম শুরুতে, একবার সূর্যোদয়ের ঠিক আগে, তারপর বললেন: "সময় এই দুইয়ের মাঝে।"`, fas: `همانند هر پنج نماز، فجر نیز در شب معراج هنگام صعود پیامبر ﷺ به هفت آسمان واجب شد و خداوند ابتدا پنجاه نماز روزانه را مقرر فرمود که سرانجام به پنج کاهش یافت (با پاداش پنجاه). درباره فجر به‌ویژه: جبرئیل (ع) دو روز پیاپی نزد کعبه پیشوای نماز پیامبر ﷺ شد تا وقت آن را تعلیم دهد: یک بار در آغاز فجر و یک بار اندکی پیش از طلوع، سپس فرمود: "وقت میان این دو است."`, zh: `与五时拜功一样，晨礼亦在登霄之夜被定为主命，时先知ﷺ升上七重天，真主最初降命每日五十次拜功，最终减为五次（仍获五十之回赐）。关于晨礼，吉卜利里（愿主赐他平安）连续两日在天房旁带领先知ﷺ礼此功修以教其时段：一次在破晓之始，一次在日出之前，然后说："时段在此二者之间。"`, yue: `同五時拜功一樣，晨禮亦喺登霄之夜被定為主命，當時先知ﷺ升上七重天，真主最初降命每日五十次拜功，最終減為五次（仍獲五十之回賜）。關於晨禮，吉卜利里（願主賜佢平安）連續兩日喺天房旁帶領先知ﷺ禮呢個功修以教其時段：一次喺破曉之始，一次喺日出之前，然後話：「時段喺此二者之間。」`, ja: `五時の礼拝と同様、ファジュルもミウラージュの夜、預言者ﷺが七天に昇られた折に義務付けられた。アッラーは当初日に五十回の礼拝を命じられ、最終的に五回に減じられた（報奨は五十のまま）。特にファジュルについて、ジブリール（に平安あれ）が連続二日カアバの傍で預言者ﷺのイマームとしてこの礼拝を導き、時刻を教えた。一度は夜明けのまさに初め、一度は日の出直前。そしてこう言った。「時はこの二つの間である」。`, ru: `Как и все пять молитв, Фаджр был предписан в Ночь Вознесения, когда Пророк ﷺ восшёл через семь небес, и Аллах первоначально установил пятьдесят ежедневных молитв, в итоге сведённых к пяти (с наградой пятидесяти). Что касается Фаджра в частности: Джибриль (мир ему) возглавил в этой молитве Пророка ﷺ у Каабы дважды в течение двух дней подряд, чтобы научить времени: один раз в самом начале рассвета и один раз непосредственно перед восходом, затем сказал: "Время — между этими двумя."`, es: `Como las cinco oraciones, el Fajr fue ordenado en la Noche del Viaje, cuando el Profeta ﷺ ascendió por los siete cielos y Allah prescribió en un principio cincuenta oraciones diarias, finalmente reducidas a cinco (con la recompensa de cincuenta). En particular sobre el Fajr, Yibril (as) dirigió al Profeta ﷺ en esta oración junto a la Ka'bah dos veces en días consecutivos para enseñarle su tiempo: una al comienzo mismo del alba y otra justo antes del amanecer, y luego dijo: "El tiempo está entre estos dos."`, ko: `다섯 예배와 마찬가지로 파즈르도 미으라즈의 밤, 예언자 ﷺ께서 일곱 하늘로 오르셨을 때에 의무로 정해졌으며, 알라께서는 처음 하루 쉰 번의 예배를 명하셨다가 결국 다섯 번으로 줄이셨습니다(쉰 번의 보상으로). 특별히 파즈르에 대해서는, 지브릴(평화가 그에게)께서 카바 옆에서 예언자 ﷺ와 함께 이 예배를 이틀 연속 인도하여 그 시간을 가르치셨습니다: 한 번은 새벽이 막 시작될 때, 한 번은 일출 직전. 그러고는 말씀하셨습니다: "시간은 이 둘 사이이다."`, ta: `ஐந்து தொழுகைகளைப் போலவே, ஃபஜ்ரும் இஸ்ரா-மிஃராஜ் இரவில் கடமையாக்கப்பட்டது, அப்போது நபி ﷺ ஏழு வானங்களுக்கு உயர்த்தப்பட்டார்; அல்லாஹ் ஆரம்பத்தில் தினமும் ஐம்பது தொழுகைகளை விதித்தான், இறுதியில் ஐந்தாகக் குறைக்கப்பட்டது (ஐம்பதின் கூலியுடன்). ஃபஜ்ர் குறித்து விசேஷமாக: கஅபாவின் அருகே ஜிப்ரீல் (அலை) நபி ﷺ அவர்களுக்கு இத்தொழுகையை இரு நாட்கள் தொடர்ந்து இமாமாக நிற்று வேளையைக் கற்பித்தார்: ஒருமுறை விடியலின் தொடக்கத்திலும், ஒருமுறை சூரிய உதயத்திற்குச் சற்றுமுன்பும், பின் கூறினார்: "வேளை இவ்விரண்டிற்கும் இடையே."`, si: `පංච සලාත මෙන්ම ෆජ්ර්ද මිඃරාජ් රාත්‍රියේදී අනිවාර්ය කෙරුණි; එවිට නබි ﷺ සත් ස්වර්ග හරහා ඉහළට ගමන් කළ අතර, අල්ලාහ් ආරම්භයේදී දිනකට සලාත පනහක් නියම කළ අතර, අවසානයේ පහකට අඩු කරන ලදී (පනහේ ප්‍රතිඵලය සමඟ). ෆජ්ර් ගැන විශේෂයෙන්: ජිබ්රීල් (ඔහුට සාමය) කඃබාව අසළ පිට පිට දින දෙකක් නබි ﷺ සමඟ මෙම සලාතයේ ඉමාම් වශයෙන් සිට කාලය ඉගැන්වූහ: එක් වරක් අරුණෝදයේ ආරම්භයේදී ද, එක් වරක් හිරු උදාවට මොහොතකට පෙර ද. පසුව පැවසූහ: "කාලය මේ දෙක අතරයි."` },
  fajr_significance: { en: `Fajr is described in the Quran as "witnessed"  –  the angels of the night and the angels of the day both attend it together, with no other prayer sharing this honour. It is the dividing line between the sincere believers and the hypocrites, who find it heaviest. It opens the day with the surrender of one's faculties to Allah before the worldly demands begin, and the Prophet ﷺ said the one who prays it is "in the protection of Allah" until evening.`, ms: `Fajar disifatkan dalam al-Quran sebagai "disaksikan"  –  para malaikat malam dan para malaikat siang menghadirinya bersama-sama, suatu kelebihan yang tidak dimiliki oleh solat lain. Ia adalah garis pemisah antara mukmin sejati dan munafik, yang merasakannya paling berat. Ia membuka hari dengan penyerahan diri kepada Allah sebelum tuntutan dunia bermula, dan Nabi ﷺ bersabda orang yang mendirikannya berada "dalam perlindungan Allah" sehingga petang.`, tur: `Fecr, Kur'an'da "şâhid kılınmış"  –  gece ve gündüz melekleri birlikte ona şahit olur, başka hiçbir namaz bu şerefi paylaşmaz. Samimi mü'minler ile münafıkları ayıran çizgidir; münafıklar onu en ağır bulurlar. Dünyanın talepleri başlamadan, kişinin tüm güçlerini Allah'a teslim ederek günü açar; Peygamber ﷺ "onu kılan, akşama kadar Allah'ın güvencesindedir" buyurmuştur.`, urd: `فجر کو قرآن میں "مشہود" (مشاہدہ کیا گیا) کہا گیا ہے  –  رات کے فرشتے اور دن کے فرشتے دونوں اس میں اکٹھے حاضر ہوتے ہیں، یہ شرف کسی اور نماز کو حاصل نہیں۔ یہ سچے مومنوں اور منافقوں کے درمیان حدِ فاصل ہے، اور منافق اسے سب سے بھاری پاتے ہیں۔ یہ دن کا آغاز اللہ کے سامنے اپنی صلاحیتوں کے سپرد ہونے سے کرتی ہے، اور نبی ﷺ نے فرمایا اسے پڑھنے والا شام تک "اللہ کی پناہ میں" ہے۔`, ben: `ফজরকে কুরআনে "সাক্ষীযুক্ত" বলা হয়েছে  –  রাতের ফেরেশতা ও দিনের ফেরেশতা উভয়েই একসঙ্গে এতে হাজির হন, অন্য কোনো নামাজে এই সম্মান নেই। এটি প্রকৃত মুমিন ও মুনাফিকদের মধ্যে বিভাজনরেখা; মুনাফিকরা এটিকে সবচেয়ে কঠিন মনে করে। দুনিয়ার চাহিদা শুরু হওয়ার আগেই আল্লাহর কাছে নিজেকে সমর্পণ করে দিনের সূচনা ঘটায়, এবং নবী ﷺ বলেছেন যে এটি আদায় করে সে সন্ধ্যা পর্যন্ত "আল্লাহর হেফাজতে" থাকে।`, fas: `فجر در قرآن "مشهود" (دارای شاهدان) خوانده شده  –  فرشتگان شب و فرشتگان روز هر دو با هم در آن حاضر می‌شوند، شرفی که هیچ نماز دیگری ندارد. مرز جداکننده مؤمنان راستین از منافقان است؛ منافقان آن را گران‌ترین می‌یابند. روز را با تسلیم همه قوای انسان به خداوند، پیش از آغاز خواست‌های دنیوی، می‌گشاید و پیامبر ﷺ فرمود گزارنده آن تا شب "در پناه خداست".`, zh: `《古兰经》称晨礼为「被见证」  –  夜间天使与白昼天使一同出席，无任何其他拜功享此殊荣。它是真信士与伪信者之间的分水岭，伪信者觉其最为沉重。它在世俗事务展开之前，以将一切官能交托真主而开启一日；先知ﷺ言行此者直至日暮"皆在真主的护佑中"。`, yue: `《古蘭經》稱晨禮為「被見證」  –  夜間天使與白晝天使一同出席，無任何其他拜功享此殊榮。佢係真信士與偽信者之間嘅分水嶺，偽信者覺其最為沉重。佢喺世俗事務展開之前，以將一切官能交託真主而開啟一日；先知ﷺ言行此者直至日暮「皆喺真主嘅護佑中」。`, ja: `ファジュルはクルアーンで「立ち会われた礼拝」と称される  –  夜の天使たちと昼の天使たちが共に出席し、他のいかなる礼拝もこの栄誉を共有しない。真の信者と偽善者を分かつ境界線であり、偽善者にとっては最も重い。世俗の要求が始まる前にあらゆる力をアッラーに委ねて一日を開く礼拝で、預言者ﷺは「これを礼拝する者は夕方までアッラーの庇護にある」と言われた。`, ru: `Фаджр в Коране назван «засвидетельствованной»  –  ангелы ночи и ангелы дня присутствуют на ней вместе, и ни одна другая молитва не разделяет этой чести. Она  –  рубеж между искренними верующими и лицемерами, которым она тяжелее всего. Она открывает день предании всех способностей Аллаху прежде, чем начнутся мирские требования, и Пророк ﷺ сказал, что совершивший её «находится под защитой Аллаха» до вечера.`, es: `El Fajr es descrito en el Corán como "atestiguado"  –  los ángeles de la noche y los ángeles del día asisten juntos, un honor del que no goza ninguna otra oración. Es la línea divisoria entre los creyentes sinceros y los hipócritas, que la encuentran la más pesada. Abre el día con la entrega de las facultades a Allah antes de que comiencen las exigencias mundanas, y el Profeta ﷺ dijo que quien la reza está "bajo la protección de Allah" hasta el anochecer.`, ko: `파즈르는 꾸란에서 "증언된" 예배로 묘사됩니다  –  밤의 천사들과 낮의 천사들이 함께 참석하며, 다른 어떤 예배도 이 영예를 공유하지 않습니다. 진실한 신자와 위선자를 가르는 경계선이며, 위선자에게는 가장 무겁게 느껴집니다. 세속의 요구가 시작되기 전에 모든 능력을 알라께 맡기며 하루를 여는 예배이고, 예언자 ﷺ께서는 이를 예배하는 자가 저녁까지 "알라의 보호 안에" 있다고 말씀하셨습니다.`, ta: `ஃபஜ்ர் குர்ஆனில் "சாட்சியளிக்கப்பட்டது" என வர்ணிக்கப்படுகிறது  –  இரவின் வானவர்களும் பகலின் வானவர்களும் ஒன்றாகக் கலந்துகொள்கின்றனர், இக்கௌரவத்தை வேறு எந்தத் தொழுகையும் பெறவில்லை. உண்மை விசுவாசிகளுக்கும் நயவஞ்சகர்களுக்கும் இடையேயான பிரிவுக் கோடு; நயவஞ்சகர்கள் இதையே மிகவும் சுமையாகக் காண்கிறார்கள். உலகியல் கோரிக்கைகள் தொடங்கும் முன், ஒருவரின் அனைத்துத் திறன்களையும் அல்லாஹ்விடம் ஒப்படைத்து நாளைத் திறக்கிறது; நபி ﷺ இதைத் தொழுபவர் மாலை வரை "அல்லாஹ்வின் பாதுகாப்பில்" இருப்பார் எனக் கூறினார்.`, si: `ෆජ්ර් කුර්ආනයේ "සාක්ෂි දරන ලද" ලෙස හඳුන්වයි  –  රාත්‍රියේ මලාඉකාවරුද දවසේ මලාඉකාවරුද එහි එක්ව සහභාගි වෙති; මෙම ගෞරවය වෙනත් කිසිදු සලාතයකට හිමි නැත. සැබෑ විශ්වාසවන්තයන් හා කපටියන් අතර බෙදීමේ රේඛාව වන අතර, කපටියන්ට එය බරම ලෙස දැනේ. ලෞකික ඉල්ලීම් ආරම්භ වීමට පෙර තමන්ගේ සියලු හැකියාවන් අල්ලාහ්ට පවරා දින ආරම්භ කරයි; නබි ﷺ එය ඉටු කරන්නා සවස වන තෙක් "අල්ලාහ්ගේ ආරක්ෂාවේ" සිටින බව පැවසූහ.` },
  fajr_proof_q: { en: `"Establish prayer at the decline of the sun [from its meridian] until the darkness of the night, and the recitation of dawn (qur'an al-fajr). Indeed, the recitation of dawn is ever witnessed." (Al-Isra' 17:78). The phrase "qur'an al-fajr" specifically denotes the Fajr prayer's lengthy recitation, and "ever witnessed" refers to the night and day angels both being present.`, ms: `"Dirikanlah solat sejak gelincirnya matahari [dari titik tegaknya] hingga kegelapan malam, dan bacaan fajar (qur'an al-fajr). Sesungguhnya bacaan fajar itu sentiasa disaksikan." (Al-Isra' 17:78). Ungkapan "qur'an al-fajr" khusus merujuk kepada bacaan panjang Subuh, dan "sentiasa disaksikan" merujuk kepada kehadiran bersama malaikat malam dan siang.`, tur: `"Güneşin batıya doğru kaymasından gecenin karanlığına dek namazı dosdoğru kıl ve sabah Kur'an'ını (kur'an al-fecr). Şüphesiz sabah Kur'an'ı şahit olunan bir okumadır." (İsrâ 17:78). "Kur'an al-fecr" tabiri özellikle Sabah namazının uzun kıraatini, "şahit olunan" ise gece ve gündüz meleklerinin birlikte hazır bulunmasını ifade eder.`, urd: `"نماز قائم کرو سورج کے ڈھلنے سے رات کے اندھیرے تک، اور فجر کی قراءت (قرآن الفجر)۔ بے شک فجر کی قراءت پر گواہی دی جاتی ہے۔" (الاسراء ۱۷:۷۸)۔ "قرآن الفجر" کی تعبیر خاص طور پر نمازِ فجر کی طویل قراءت کو ظاہر کرتی ہے، اور "گواہی دی جاتی ہے" سے مراد رات و دن کے فرشتوں کا اکٹھے حاضر ہونا ہے۔`, ben: `"সূর্য ঢলে পড়া থেকে রাতের অন্ধকার পর্যন্ত নামাজ কায়েম করো, এবং ফজরের কেরাত (কুরআনুল ফজর)। নিশ্চয়ই ফজরের কেরাত সাক্ষীযুক্ত।" (আল-ইসরা ১৭:৭৮)। "কুরআনুল ফজর" বিশেষভাবে ফজর নামাজের দীর্ঘ কেরাত নির্দেশ করে, এবং "সাক্ষীযুক্ত" রাত ও দিনের ফেরেশতাদের একসঙ্গে উপস্থিতিকে নির্দেশ করে।`, fas: `"نماز را از زوال خورشید تا تاریکی شب برپا دار، و قرآن فجر (قرائت سپیده‌دم) را. به‌راستی قرائت فجر مشهود است." (الإسراء ۱۷:۷۸). تعبیر "قرآن الفجر" به‌ویژه به قرائت طولانی نماز فجر اشاره دارد و "مشهود" به حضور همزمان فرشتگان شب و روز.`, zh: `「自日西斜直到夜暗，你当谨守拜功，并谨守晨礼之诵读（古尔安·法吉尔）。晨礼之诵读必被见证。」（夜行章17:78）「古尔安·法吉尔」一词专指晨礼的长段诵读，「必被见证」即指夜间与白昼天使一同出席。`, yue: `「自日西斜直到夜暗，你當謹守拜功，並謹守晨禮之誦讀（古爾安·法吉爾）。晨禮之誦讀必被見證。」（夜行章17:78）「古爾安·法吉爾」一詞專指晨禮嘅長段誦讀，「必被見證」即指夜間與白晝天使一同出席。`, ja: `「太陽が傾く時から夜の暗闇に至るまで礼拝を確立せよ。そして夜明けの朗誦（クルアーン・アル＝ファジュル）を。まことに、夜明けの朗誦は常に立ち会われている。」（夜の旅章 17:78）「クルアーン・アル＝ファジュル」の語は特にファジュル礼拝の長い朗誦を指し、「常に立ち会われる」とは夜と昼の天使がともに居合わせることを意味する。`, ru: `«Совершай молитву от склонения солнца [с зенита] до наступления ночной тьмы, и чтение на рассвете (кур'ан аль-фаджр). Поистине, чтение на рассвете всегда засвидетельствовано.» (Аль-Исра 17:78). Выражение «кур'ан аль-фаджр» относится именно к продолжительному чтению Фаджра, а «всегда засвидетельствовано»  –  к одновременному присутствию ангелов ночи и дня.`, es: `"Establece la oración desde la declinación del sol [desde su meridiano] hasta la oscuridad de la noche, y la recitación del alba (qur'an al-fajr). En verdad, la recitación del alba siempre es atestiguada." (Al-Isra' 17:78). La expresión "qur'an al-fajr" se refiere específicamente a la recitación extensa del Fajr, y "siempre atestiguada" alude a la presencia conjunta de los ángeles de la noche y del día.`, ko: `"태양이 [정점에서] 기울 때부터 밤의 어둠까지 예배를 세우고, 새벽의 낭송(꾸르안 알파즈르)을 [세우라]. 진실로 새벽의 낭송은 항상 증언되니라." (알이스라 17:78) "꾸르안 알파즈르"라는 구는 특별히 파즈르 예배의 긴 낭송을 가리키며, "항상 증언된다"는 것은 밤과 낮의 천사들이 함께 임함을 뜻한다.`, ta: `"சூரியன் [உச்சியிலிருந்து] சாயத் தொடங்கியதிலிருந்து இரவின் இருள் வரை தொழுகையை நிலைநிறுத்துவீராக, மற்றும் விடியலின் ஓதலை (குர்ஆனுல் ஃபஜ்ர்). நிச்சயமாக விடியலின் ஓதல் சாட்சியளிக்கப்படுவதாகும்." (அல்-இஸ்ரா 17:78). "குர்ஆனுல் ஃபஜ்ர்" என்னும் சொற்றொடர் ஃபஜ்ர் தொழுகையின் நீண்ட ஓதலையே குறிக்கிறது, மேலும் "சாட்சியளிக்கப்படுவது" என்பது இரவு பகல் வானவர்களின் ஒன்றுசேர் கலந்துகொள்ளலைக் குறிக்கிறது.`, si: `"සූර්යයාගේ බැසීමේ සිට රාත්‍රියේ අන්ධකාරය දක්වා සලාතය ස්ථාපිත කරන්න, සහ අරුණෝදයේ පාරායනය (කුර්ආන් අල්-ෆජ්ර්). සැබැවින්ම අරුණෝදයේ පාරායනය සැමවිටම සාක්ෂි දරනු ලැබේ." (අල්-ඉස්රා 17:78). "කුර්ආන් අල්-ෆජ්ර්" යන වදන විශේෂයෙන් ෆජ්ර් සලාතයේ දිගු පාරායනය හඟවන අතර, "සැමවිටම සාක්ෂි දරනු ලැබේ" යනු රාත්‍රී හා දිවා මලාඉකාවරුන් එක්ව සහභාගි වීම යි.` },
  fajr_proof_h: { en: `The Prophet ﷺ said: "Whoever prays the Fajr prayer is in the protection of Allah." (Muslim 657). He also said: "The two cool prayers  –  whoever prays them will enter Paradise." (Bukhari 574, Muslim 635). When asked about the "two cool prayers," the Companions explained: Fajr and Asr. Abu Hurayrah (ra) reported that the angels of the night and the angels of the day gather at Fajr, ascend together, and the angels of the day stay; this is the witnessing referred to in the verse.`, ms: `Nabi ﷺ bersabda: "Sesiapa yang mendirikan solat Subuh, dia berada dalam perlindungan Allah." (Muslim 657). Baginda juga bersabda: "Dua solat sejuk  –  sesiapa yang mendirikannya akan masuk syurga." (Bukhari 574, Muslim 635). Apabila ditanya tentang "dua solat sejuk", para sahabat menjelaskan: Subuh dan Asar. Abu Hurayrah (ra) meriwayatkan bahawa malaikat malam dan malaikat siang berhimpun pada waktu Subuh, naik bersama, dan malaikat siang tinggal; inilah penyaksian yang dimaksudkan dalam ayat.`, tur: `Peygamber ﷺ buyurdu: "Sabah namazını kılan kişi Allah'ın güvencesindedir." (Müslim 657). Yine: "İki serinlik namazını  –  kim onları kılarsa cennete girer." (Buhârî 574, Müslim 635). "İki serinlik namazı" sorulduğunda sahabe Sabah ve İkindi olduğunu açıkladı. Ebû Hureyre (ra) rivayet etti ki gece ve gündüz melekleri Sabah'ta toplanır, birlikte yükselirler ve gündüz melekleri kalır; âyetteki şahitlik budur.`, urd: `نبی ﷺ نے فرمایا: "جو فجر کی نماز پڑھتا ہے، وہ اللہ کی پناہ میں ہے۔" (مسلم ۶۵۷)۔ نیز: "دو ٹھنڈی نمازیں  –  جو انہیں پڑھے، جنت میں داخل ہو گا۔" (بخاری ۵۷۴، مسلم ۶۳۵)۔ "دو ٹھنڈی نمازوں" کے بارے میں پوچھے جانے پر صحابہ نے بیان فرمایا: فجر اور عصر۔ ابو ہریرہ (رض) نے روایت کیا کہ رات اور دن کے فرشتے فجر کے وقت اکٹھے ہوتے ہیں، اوپر چڑھتے ہیں، اور دن کے فرشتے باقی رہتے ہیں؛ یہی وہ گواہی ہے جس کا ذکر آیت میں ہے۔`, ben: `নবী ﷺ বলেছেন: "যে ফজরের নামাজ পড়ে, সে আল্লাহর হেফাজতে।" (মুসলিম ৬৫৭)। আরও বলেছেন: "দুই শীতল নামাজ  –  যে এগুলো পড়বে সে জান্নাতে প্রবেশ করবে।" (বুখারি ৫৭৪, মুসলিম ৬৩৫)। "দুই শীতল নামাজ" সম্পর্কে জিজ্ঞাসিত হলে সাহাবিগণ ব্যাখ্যা করেন: ফজর ও আসর। আবু হুরায়রা (রা) বর্ণনা করেন রাতের ও দিনের ফেরেশতা ফজরে একত্রিত হন, একসঙ্গে ঊর্ধ্বগামী হন, এবং দিনের ফেরেশতারা থেকে যান; এটিই আয়াতে উল্লেখিত সাক্ষ্য।`, fas: `پیامبر ﷺ فرمود: "هرکس نماز فجر را بگزارد، در پناه خداست." (مسلم ۶۵۷). همچنین فرمود: "دو نماز خنک  –  هرکس آن دو را بگزارد، به بهشت وارد می‌شود." (بخاری ۵۷۴، مسلم ۶۳۵). چون از "دو نماز خنک" پرسیدند، صحابه گفتند: فجر و عصر. ابوهریره (رض) روایت کرد که فرشتگان شب و فرشتگان روز هنگام فجر گرد می‌آیند، با هم بالا می‌روند و فرشتگان روز می‌مانند؛ این همان شهودی است که در آیه آمده.`, zh: `先知ﷺ言："凡礼晨礼者，皆在真主的护佑中。"（穆斯林657）又言："两次凉时拜  –  凡礼此二者必入乐园。"（布哈里574，穆斯林635）问及"两次凉时拜"时，圣门弟子解释为：晨礼与晡礼。艾布·胡赖赖（愿主喜悦之）传述：夜间天使与白昼天使在晨礼时聚集，同升而去，白昼天使留下；此即经文所言之"被见证"。`, yue: `先知ﷺ言：「凡禮晨禮者，皆喺真主嘅護佑中。」（穆斯林657）又言：「兩次涼時拜  –  凡禮此二者必入樂園。」（布哈里574，穆斯林635）問及「兩次涼時拜」時，聖門弟子解釋為：晨禮與晡禮。艾布·胡賴賴（願主喜悅之）傳述：夜間天使與白晝天使喺晨禮時聚集，同升而去，白晝天使留低；此即經文所言之「被見證」。`, ja: `預言者ﷺは言われた。「ファジュル礼拝を行う者はアッラーの庇護にある。」（ムスリム657）。また仰せられた。「二つの涼しい礼拝  –  これを礼拝する者は楽園に入る。」（ブハーリー574、ムスリム635）。「二つの涼しい礼拝」とは何かを問われ、教友たちはファジュルとアスルだと答えた。アブー・フライラ（ラ）は伝える：夜の天使と昼の天使はファジュル時に集まり、共に昇って行き、昼の天使が留まる。これが節で言われる「立ち会い」である。`, ru: `Пророк ﷺ сказал: «Тот, кто совершит молитву Фаджр, под защитой Аллаха.» (Муслим 657). Он также сказал: «Две прохладные молитвы  –  кто совершит их, войдёт в Рай.» (Бухари 574, Муслим 635). Когда сподвижников спросили о «двух прохладных молитвах», они пояснили: Фаджр и Аср. Абу Хурайра (ра) передал, что ангелы ночи и ангелы дня собираются на Фаджре, поднимаются вместе, а ангелы дня остаются; это и есть засвидетельствование, упомянутое в аяте.`, es: `El Profeta ﷺ dijo: "Quien reza la oración del Fajr está bajo la protección de Allah." (Muslim 657). También dijo: "Las dos oraciones frescas  –  quien las reza entrará al Paraíso." (Bujari 574, Muslim 635). Al preguntar por las "dos oraciones frescas," los Compañeros explicaron: Fajr y Asr. Abu Hurayrah (ra) relató que los ángeles de la noche y los ángeles del día se reúnen en el Fajr, ascienden juntos, y los ángeles del día permanecen; este es el atestiguamiento al que se refiere el versículo.`, ko: `예언자 ﷺ께서 말씀하셨다: "파즈르 예배를 행하는 자는 알라의 보호 안에 있다." (무슬림 657). 또한 말씀하셨다: "두 시원한 예배  –  이를 행하는 자는 천국에 들어갈 것이다." (부카리 574, 무슬림 635). 동료들이 "두 시원한 예배"가 무엇인지 묻자 그들은 답하였다: 파즈르와 아스르. 아부 후라이라(라)께서는 전한다: 밤의 천사와 낮의 천사가 파즈르 시에 모이고 함께 올라가며, 낮의 천사가 남는다; 이것이 구절에서 언급된 증언이다.`, ta: `நபி ﷺ கூறினார்: "ஃபஜ்ர் தொழுகையைத் தொழுபவர் அல்லாஹ்வின் பாதுகாப்பில் இருக்கிறார்." (முஸ்லிம் 657). மேலும்: "இரு குளிர்ந்த தொழுகைகள்  –  இவ்விரண்டையும் தொழுபவர் சொர்க்கம் நுழைவார்." (புகாரி 574, முஸ்லிம் 635). "இரு குளிர்ந்த தொழுகைகள்" எவை எனக் கேட்கப்பட்டபோது தோழர்கள் விளக்கினார்கள்: ஃபஜ்ர் மற்றும் அஸ்ர். அபூ ஹுரைரா (ரழி) அறிவித்தார்: இரவின் வானவர்களும் பகலின் வானவர்களும் ஃபஜ்ரின்போது கூடி, ஒன்றாக மேலேறிச் செல்கின்றனர், பகலின் வானவர்கள் தங்குகின்றனர்; இதுவே வசனத்தில் குறிப்பிடப்படும் சாட்சி.`, si: `නබි ﷺ පැවසූහ: "ෆජ්ර් සලාතය ඉටු කරන්නා අල්ලාහ්ගේ ආරක්ෂාවේ සිටී." (මුස්ලිම් 657). තවද පැවසූහ: "සිසිල් සලාත දෙක  –  ඒවා ඉටු කරන්නා ස්වර්ගයට පිවිසෙයි." (බුහාරි 574, මුස්ලිම් 635). "සිසිල් සලාත දෙක" කවරේදැයි විමසූ විට සහචරයන් පැහැදිලි කළහ: ෆජ්ර් සහ අස්ර්. අබූ හුරෛරා (රළි) වාර්තා කළේ රාත්‍රියේ මලාඉකාවරුද දවසේ මලාඉකාවරුද ෆජ්ර්හි එක්රැස් වී, එක්ව ඉහළට යන අතර, දවසේ මලාඉකාවරු රැඳී සිටින බවය; මෙය වැකියේ සඳහන් සාක්ෂි දැරීමයි.` },
  fajr_recitation: { en: `Recited aloud (jahri). The Sunnah is to lengthen the recitation here more than any other prayer  –  often 60 to 100 verses in total. The Prophet ﷺ frequently recited Surah Qaf (50), al-Waqi'ah (56), al-Mursalat (77), at-Takwir (81), or similar surahs of the latter half of the Quran. On Friday Fajr specifically, the Sunnah is to recite Surah as-Sajdah (32) in the first rak'ah and Surah al-Insan (76) in the second  –  the only two surahs reported to contain Sunnah sujud al-tilawah in this prayer.`, ms: `Dibaca dengan suara kuat (jahri). Sunnah memanjangkan bacaan di sini lebih daripada solat lain  –  selalunya 60 hingga 100 ayat secara keseluruhan. Nabi ﷺ kerap membaca Surah Qaf (50), al-Waqi'ah (56), al-Mursalat (77), at-Takwir (81), atau surah-surah seumpamanya dari separuh akhir al-Quran. Pada Subuh hari Jumaat khususnya, sunnah membaca Surah as-Sajdah (32) pada rakaat pertama dan Surah al-Insan (76) pada rakaat kedua  –  dua-duanya mengandungi sujud tilawah yang disyariatkan dalam solat ini.`, tur: `Cehrî (sesli) okunur. Sünnet, burada kıraati diğer namazlardan daha uzun tutmaktır  –  genellikle toplam 60-100 âyet. Peygamber ﷺ sıkça Kaf (50), Vâkıa (56), Mürselât (77), Tekvîr (81) gibi Kur'an'ın ikinci yarısının surelerini okurdu. Özellikle Cuma sabahında, ilk rekâtta Secde (32) ve ikinci rekâtta İnsân (76) okumak sünnettir  –  bu namazda tilavet secdesi rivayet edilen iki sureden ibarettir.`, urd: `جہراً (بلند آواز) سے۔ سنّت یہ ہے کہ یہاں قراءت دیگر نمازوں سے زیادہ طویل ہو  –  اکثر مجموعی طور پر ۶۰ سے ۱۰۰ آیات۔ نبی ﷺ اکثر سورۃ ق (۵۰)، الواقعہ (۵۶)، المرسلات (۷۷)، التکویر (۸۱)، یا قرآن کے دوسرے نصف کی ایسی ہی سورتیں پڑھتے۔ خاص جمعہ کی فجر میں سنّت ہے کہ پہلی رکعت میں سورۃ السجدہ (۳۲) اور دوسری میں سورۃ الإنسان (۷۶) پڑھی جائے  –  اس نماز میں سجدہ تلاوت کے ساتھ مرفوع روایات صرف انہی دو سورتوں میں ہیں۔`, ben: `উচ্চস্বরে (জাহরি)। সুন্নাহ এখানে অন্যান্য নামাজের তুলনায় কেরাত দীর্ঘতর করা  –  সাধারণত মোট ৬০ থেকে ১০০ আয়াত। নবী ﷺ প্রায়ই সূরা কাফ (৫০), আল-ওয়াকিয়াহ (৫৬), আল-মুরসালাত (৭৭), আত-তাকউইর (৮১), বা কুরআনের শেষ অর্ধাংশের অনুরূপ সূরা পড়তেন। বিশেষত শুক্রবারের ফজরে সুন্নাহ হলো প্রথম রাকাতে সূরা আস-সাজদাহ (৩২) এবং দ্বিতীয়টিতে সূরা আল-ইনসান (৭৬) পড়া  –  এই নামাজে সিজদা তিলাওয়াত সম্বলিত যে দুটি সূরা সুন্নাহ হিসাবে বর্ণিত।`, fas: `با صدای بلند (جهری). سنت آن است که قرائت در اینجا از سایر نمازها طولانی‌تر باشد  –  معمولاً در مجموع ۶۰ تا ۱۰۰ آیه. پیامبر ﷺ اغلب سوره ق (۵۰)، واقعه (۵۶)، مرسلات (۷۷)، تکویر (۸۱) یا سوره‌های مشابه از نیمه دوم قرآن را تلاوت می‌کرد. به‌ویژه در فجر روز جمعه، سنت است در رکعت اول سوره سجده (۳۲) و در رکعت دوم سوره انسان (۷۶) خوانده شود  –  تنها دو سوره‌ای که در این نماز سجده تلاوت سنت برای آنها روایت شده.`, zh: `高声诵读（贾赫里）。圣行是于此处诵读较其他拜功更长  –  通常合计60至100节。先知ﷺ常诵读《戛弗》（50）、《大事》（56）、《奉使者》（77）、《卷起》（81）或《古兰经》后半部之类经章。特别于主麻日晨礼，圣行为首拜诵《叩头章》（32）、次拜诵《人章》（76）  –  此乃此功修中带"诵读叩头"之圣行而见诸传报的两章。`, yue: `高聲誦讀（賈赫里）。聖行係於此處誦讀較其他拜功更長  –  通常合計60至100節。先知ﷺ常誦讀《戛弗》（50）、《大事》（56）、《奉使者》（77）、《捲起》（81）或《古蘭經》後半部之類經章。特別於主麻日晨禮，聖行為首拜誦《叩頭章》（32）、次拜誦《人章》（76）  –  此乃此功修中帶「誦讀叩頭」之聖行而見諸傳報嘅兩章。`, ja: `声に出して（ジャフリー）朗誦する。スンナはここで他のどの礼拝よりも長く朗誦すること  –  通常合計60～100節。預言者ﷺは頻繁にカーフ章（50）、ワーキア章（56）、ムルサラート章（77）、タクウィール章（81）など、クルアーン後半の章を朗誦された。特に金曜日のファジュルでは、第一ラクアでサジダ章（32）、第二ラクアでインサーン章（76）を朗誦するのがスンナ  –  この礼拝で朗誦の平伏（スジュード・アッ＝ティラーワ）がスンナとして伝えられる二章のみである。`, ru: `Читается вслух (джахрий). Сунна  –  здесь удлинять чтение больше, чем в любой другой молитве  –  часто всего 60–100 аятов. Пророк ﷺ часто читал суру Каф (50), аль-Вакиа (56), аль-Мурсалят (77), ат-Таквир (81) или подобные суры второй половины Корана. Конкретно в пятничный Фаджр сунной является чтение суры ас-Саджда (32) в первом ракате и суры аль-Инсан (76) во втором  –  это две суры, для которых в этой молитве передан сунновский саджда тилявы.`, es: `Se recita en voz alta (jahri). La Sunnah es alargar aquí la recitación más que en cualquier otra oración  –  a menudo de 60 a 100 versículos en total. El Profeta ﷺ recitaba con frecuencia la Sura Qaf (50), al-Waqi'ah (56), al-Mursalat (77), at-Takwir (81), o suras similares de la segunda mitad del Corán. Específicamente en el Fajr del viernes, la Sunnah es recitar la Sura as-Sajdah (32) en el primer rak'ah y la Sura al-Insan (76) en el segundo  –  las únicas dos suras de las que se reporta que en esta oración contengan la sujud al-tilawah sunnah.`, ko: `소리 내어(자흐리) 낭송. 순나는 여기서 다른 어떤 예배보다도 낭송을 길게 하는 것  –  보통 전체 60~100 구절. 예언자 ﷺ께서는 자주 카프 장(50), 알와끼아(56), 알무르살라트(77), 앗타크위르(81) 등 꾸란 후반부 장들을 낭송하셨습니다. 특별히 금요일 파즈르에는 첫 라카에서 앗사즈다 장(32), 둘째에서 알인산 장(76)을 낭송하는 것이 순나  –  이 예배에서 낭송 엎드림(수주드 알틸라와)이 순나로 보고된 두 장입니다.`, ta: `உரக்க (ஜஹ்ரி) ஓதப்படுகிறது. சுன்னா இங்கே மற்ற எந்தத் தொழுகையை விடவும் ஓதலை நீட்டுவது  –  பெரும்பாலும் மொத்தம் 60 முதல் 100 வசனங்கள் வரை. நபி ﷺ அடிக்கடி சூரத்து காஃப் (50), அல்-வாகிஆ (56), அல்-முர்ஸலாத் (77), அத்-தக்வீர் (81), அல்லது குர்ஆனின் பிற்பகுதியின் இதுபோன்ற சூராக்களை ஓதினார். குறிப்பாக வெள்ளிக்கிழமை ஃபஜ்ரில், முதல் ரக்அத்தில் சூரத்துஸ்-ஸஜ்தா (32) மற்றும் இரண்டாவதில் சூரத்துல்-இன்ஸான் (76) ஓதுவது சுன்னா  –  இத்தொழுகையில் ஓதல் சுஜூத் (சுஜூத் அத்-திலாவா) சுன்னாவாக அறிவிக்கப்பட்ட இரு சூராக்கள் இவையே.`, si: `හඬ නඟා (ජහ්රී) කියවයි. සුන්නාව වන්නේ වෙනත් කවර සලාතයකටත් වඩා මෙහි කියවීම දිගු කිරීමයි  –  සාමාන්‍යයෙන් මුළු වැකි 60 සිට 100 දක්වා. නබි ﷺ බොහෝ විට කාෆ් (50), අල්-වාකිඃඃඃ (56), අල්-මුර්සලාත් (77), අත්-තක්වීර් (81), හෝ කුර්ආනයේ දෙවන භාගයේ එවැනි සූරාවන් කියවූහ. විශේෂයෙන් සිකුරාදා ෆජ්ර්හිදී, පළමු රකඅතේ අස්-සජ්දා (32) සහ දෙවැන්නේ අල්-ඉන්සාන් (76) කියවීම සුන්නාව  –  මෙම සලාතයේ පාරායන සජ්දාව (සජ්දත් අත්-තිලාවා) සුන්නාවක් ලෙස වාර්තා වූ එකම සූරා දෙකකි.` },
  fajr_sunnah_say: { en: `In the two Sunnah rak'ahs of Fajr, the Prophet ﷺ recited very short surahs: in the first rak'ah Surah al-Kafirun (109) or "Qulu amanna billahi..." (2:136), and in the second Surah al-Ikhlas (112) or "Qul ya ahla al-kitab..." (3:64). Make the two Sunnah rak'ahs short and the two fard long. Between the two Sunnah and the fard, supplicate quietly; the dawn is one of the times du'a is most accepted. Before the prayer, on rising from sleep, say "Alhamdu lillahi-lladhi ahyana ba'da ma amatana wa ilayhin-nushur".`, ms: `Dalam dua rakaat sunat Subuh, Nabi ﷺ membaca surah-surah sangat pendek: rakaat pertama Surah al-Kafirun (109) atau "Qulu amanna billahi..." (2:136), rakaat kedua Surah al-Ikhlas (112) atau "Qul ya ahla al-kitab..." (3:64). Pendekkan dua rakaat sunat, panjangkan dua rakaat fardu. Antara sunat dan fardu, berdoalah secara senyap; fajar adalah antara waktu doa paling makbul. Sebelum solat, ketika bangun tidur, ucap "Alhamdu lillahi-lladhi ahyana ba'da ma amatana wa ilayhin-nushur".`, tur: `Sabahın iki sünnetinde Peygamber ﷺ çok kısa sureler okurdu: ilk rekâtta Kâfirûn (109) veya "Kûlû âmennâ billâhi..." (2:136), ikinci rekâtta İhlâs (112) veya "Kul yâ ehlel-kitâb..." (3:64). İki sünneti kısa, iki farzı uzun tut. Sünnetle farz arasında sessizce dua et; fecir, duanın en makbul vakitlerindendir. Namazdan önce, uykudan kalkınca "Elhamdü lillâhillezî ahyânâ ba'de mâ emâtenâ ve ileyhin-nüşûr" de.`, urd: `فجر کی دو سنّتوں میں نبی ﷺ بہت چھوٹی سورتیں پڑھتے: پہلی رکعت میں سورۃ الکافرون (۱۰۹) یا "قولوا آمنا باللہ..." (۲:۱۳۶)، دوسری میں سورۃ الإخلاص (۱۱۲) یا "قل یا أہل الکتاب..." (۳:۶۴)۔ دو سنّتیں مختصر رکھیں اور دو فرض طویل۔ سنّت اور فرض کے درمیان آہستہ سے دعا کریں؛ فجر دعا کی قبولیت کے بہترین اوقات میں سے ہے۔ نماز سے پہلے، نیند سے اٹھتے ہوئے کہیں: "الحمد للہ الذي أحیانا بعد ما أماتنا و إلیہ النشور"۔`, ben: `ফজরের দুই সুন্নাহ রাকাতে নবী ﷺ অত্যন্ত ছোট সূরা পড়তেন: প্রথম রাকাতে সূরা আল-কাফিরূন (১০৯) বা "কূলূ আমান্না বিল্লাহি..." (২:১৩৬), দ্বিতীয়টিতে সূরা আল-ইখলাস (১১২) বা "কুল ইয়া আহলাল কিতাব..." (৩:৬৪)। দুই সুন্নাহ সংক্ষিপ্ত, দুই ফরজ দীর্ঘ। সুন্নাহ ও ফরজের মাঝে নীরবে দোয়া করুন; ফজর হলো দোয়া কবুলের সর্বাধিক উত্তম সময়সমূহের একটি। নামাজের আগে, ঘুম থেকে উঠে বলুন: "আলহামদু লিল্লাহিল্লাযী আহইয়ানা বা'দা মা আমাতানা ওয়া ইলাইহিন-নুশূর"।`, fas: `در دو رکعت سنت فجر، پیامبر ﷺ سوره‌های بسیار کوتاه می‌خواند: در رکعت اول سوره کافرون (۱۰۹) یا "قولوا آمنا بالله..." (۲:۱۳۶) و در رکعت دوم سوره اخلاص (۱۱۲) یا "قل یا أهل الکتاب..." (۳:۶۴). دو سنت را کوتاه و دو فرض را بلند بگذار. میان سنت و فرض آرام دعا کن؛ فجر از زمان‌های پراجابت‌ترین دعاست. پیش از نماز، هنگام بیداری از خواب بگو: "الحمد لله الذي أحیانا بعد ما أماتنا و إلیه النشور".`, zh: `在晨礼前的两拜圣行中，先知ﷺ诵读极短的章：首拜诵《不信者章》（109）或「Qulu amanna billahi…」（2:136），次拜诵《忠诚章》（112）或「Qul ya ahla al-kitab…」（3:64）。两拜圣行从短，两拜主命则长。圣行与主命之间静默祈祷；破晓乃祈祷最易被应答的时段之一。礼前自睡眠中起身时诵：「Alhamdu lillahi-lladhi ahyana ba'da ma amatana wa ilayhin-nushur」。`, yue: `喺晨禮前嘅兩拜聖行中，先知ﷺ誦讀極短嘅章：首拜誦《不信者章》（109）或「Qulu amanna billahi…」（2:136），次拜誦《忠誠章》（112）或「Qul ya ahla al-kitab…」（3:64）。兩拜聖行宜短，兩拜主命則長。聖行與主命之間靜默祈禱；破曉乃祈禱最易被應答嘅時段之一。禮前自睡眠中起身時誦：「Alhamdu lillahi-lladhi ahyana ba'da ma amatana wa ilayhin-nushur」。`, ja: `ファジュル前の二ラクアのスンナで、預言者ﷺは非常に短い章を朗誦された：第一ラクアでカーフィルーン章（109）または「クールー・アーマンナー・ビッラーヒ…」（2:136）、第二ラクアでイフラース章（112）または「クル・ヤー・アフラル＝キターブ…」（3:64）。二ラクアのスンナは短く、二ラクアのファルドは長くする。スンナとファルドの間に静かにドゥアする  –  夜明けはドゥアが最も受け入れられる時の一つ。礼拝前、寝覚めの際には「アルハムドゥ・リッラーヒッラジー・アヒヤーナー・バアダ・マー・アマータナー・ワ・イライヒンヌシュール」と唱える。`, ru: `В двух ракатах сунны Фаджра Пророк ﷺ читал очень короткие суры: в первом — суру аль-Кафирун (109) или «Кулу амання биллахи…» (2:136), во втором — суру аль-Ихляс (112) или «Куль йа ахль аль-китаб…» (3:64). Сделай два раката сунны короткими, а два раката фарда длинными. Между сунной и фардом тихо взывай  –  рассвет одно из самых принимаемых времён дуа. Перед молитвой, при пробуждении ото сна, произнеси «Альхамду лилляхиль-лази ахьяна баада ма аматана ва иляйхин-нушур».`, es: `En los dos rak'ahs Sunnah del Fajr, el Profeta ﷺ recitaba suras muy breves: en el primer rak'ah la Sura al-Kafirun (109) o "Qulu amanna billahi..." (2:136), y en el segundo la Sura al-Ikhlas (112) o "Qul ya ahla al-kitab..." (3:64). Haz cortos los dos rak'ahs Sunnah y largos los dos del fard. Entre la Sunnah y el fard, suplica en silencio; el alba es uno de los tiempos en que el du'a es más aceptado. Antes de la oración, al levantarse del sueño, di "Alhamdu lillahi-lladhi ahyana ba'da ma amatana wa ilayhin-nushur".`, ko: `파즈르의 두 순나 라카에서 예언자 ﷺ께서는 아주 짧은 장을 낭송하셨다: 첫 라카에서 알카피룬 장(109) 또는 "꿀루 아만나 빌라히…"(2:136), 둘째에서 알이클라스 장(112) 또는 "꿀 야 아흘랄 키타브…"(3:64). 두 순나 라카는 짧게, 두 파르드 라카는 길게 하라. 순나와 파르드 사이에 조용히 기원하라  –  새벽은 두아가 가장 잘 받아들여지는 때 중 하나이다. 예배 전, 잠에서 깨면 "알함두 릴라힐 라디 아하야나 바으다 마 아마타나 와 일라이힌누슈르"를 말하라.`, ta: `ஃபஜ்ர் சுன்னா இரண்டு ரக்அத்களில் நபி ﷺ மிகக் குறுகிய சூராக்கள் ஓதினார்: முதல் ரக்அத்தில் சூரத்துல்-காஃபிரூன் (109) அல்லது "குலூ ஆமன்னா பில்லாஹி..." (2:136), இரண்டாவதில் சூரத்துல்-இக்லாஸ் (112) அல்லது "குல் யா அஹ்லல் கிதாப்..." (3:64). இரு சுன்னா ரக்அத்களைச் சுருக்கி, இரு ஃபர்ள் ரக்அத்களை நீட்டுங்கள். சுன்னாவுக்கும் ஃபர்ளுக்கும் இடையே அமைதியாக துஆ செய்யுங்கள்  –  துஆ அதிகம் ஏற்கப்படும் வேளைகளில் விடியல் ஒன்று. தொழுகைக்கு முன், உறக்கத்திலிருந்து எழும்போது சொல்லுங்கள்: "அல்ஹம்து லில்லாஹில்லதீ அஹ்யானா பஃத மா அமாதனா வ இலைஹின்-நுஷூர்".`, si: `ෆජ්ර්හි සුන්නා රකඅත් දෙකේදී නබි ﷺ ඉතා කෙටි සූරා කියවූහ: පළමු රකඅතේදී අල්-කාෆිරූන් සූරාව (109) හෝ "කූලූ ආමන්නා බිල්ලාහි..." (2:136), දෙවැන්නේදී අල්-ඉක්ලාස් සූරාව (112) හෝ "කුල් යා අහ්ලල් කිතාබ්..." (3:64). සුන්නා රකඅත් දෙක කෙටි කොට, ෆර්ද් රකඅත් දෙක දිගු කරන්න. සුන්නාව හා ෆර්ද් අතර නිහඬව ප්‍රාර්ථනා කරන්න  –  දුආ වැඩි පිළිගැනීමක් ලැබෙන මොහොත අතර අරුණෝදය එකකි. සලාතයට පෙර, නින්දෙන් අවදි වන විට කියන්න: "අල්හම්දු ලිල්ලාහිල්ලදී අහ්යානා බඃද මා අමාතනා ව ඉලෛහින්-නුෂූර්".` },
  fajr_extras_say: { en: `After the fard salam, in addition to the universal post-prayer adhkar: the morning adhkar (adhkar al-sabah) are due now and remain valid until sunrise. Among them: Ayat al-Kursi, the three Quls each three times with blowing into the palms, "Hasbiyallahu la ilaha illa huwa, 'alayhi tawakkaltu wa huwa Rabbul-'Arshil-'Azim" (seven times), and "Allahumma bika asbahna wa bika amsayna...". After completing the morning adhkar, remain seated in the place of prayer until sunrise, then pray two rak'ahs of "Ishraq"; the Prophet ﷺ said this carries the reward of a complete Hajj and Umrah.`, ms: `Selepas salam fardu, sebagai tambahan kepada zikir umum selepas solat: zikir pagi (adhkar al-sabah) jatuh tempo sekarang dan sah sehingga matahari terbit. Antaranya: Ayat al-Kursi, tiga Qul setiap satu tiga kali sambil meniup ke tapak tangan, "Hasbiyallahu la ilaha illa huwa, 'alayhi tawakkaltu wa huwa Rabbul-'Arshil-'Azim" (tujuh kali), dan "Allahumma bika asbahna wa bika amsayna...". Selepas selesai zikir pagi, duduk di tempat solat sehingga matahari terbit, kemudian dirikan dua rakaat "Isyraq"; Nabi ﷺ bersabda ini membawa pahala satu Haji dan Umrah yang sempurna.`, tur: `Farzın selamından sonra, namaz sonrası genel zikirlere ek olarak: sabah zikirleri (ezkâru's-sabâh) zamanı gelmiştir ve güneş doğana kadar geçerlidir. Bunlardan: Âyetü'l-Kürsî; üç "Kul" suresi her biri üç defa avuçlara üflenerek; "Hasbiyallâhu lâ ilâhe illâ Hû, aleyhi tevekkeltü ve Hüve Rabbül-Arşil-Azîm" (yedi defa); ve "Allâhümme bike asbahnâ ve bike emseynâ..." Sabah zikirleri bittikten sonra güneş doğana kadar namaz yerinde otur, sonra iki rekât "İşrak" namazı kıl; Peygamber ﷺ bunun tam bir hac ve umre sevabını taşıdığını buyurmuştur.`, urd: `فرض کے سلام کے بعد، عمومی بعد از نماز اذکار کے علاوہ: اذکارِ صبح کا وقت اب شروع ہوتا ہے اور طلوعِ آفتاب تک رہتا ہے۔ ان میں: آیت الکرسی؛ تین قل ہر ایک تین بار ہتھیلیوں میں پھونک کر؛ "حسبي اللہ لا إلہ إلا ہو علیہ توکلت وہو رب العرش العظیم" (سات بار)؛ "اللہم بک أصبحنا و بک أمسینا..."۔ اذکارِ صبح ختم کرنے کے بعد طلوعِ آفتاب تک نمازی جگہ پر بیٹھے رہیں، پھر دو رکعت "اشراق" پڑھیں؛ نبی ﷺ نے فرمایا یہ ایک مکمل حج اور عمرہ کا ثواب رکھتا ہے۔`, ben: `ফরজের সালামের পরে, সাধারণ নামাজোত্তর জিকিরের পাশাপাশি: সকালের জিকিরের (আযকার আস-সাবাহ) সময় এখন শুরু হয় এবং সূর্যোদয় পর্যন্ত বৈধ থাকে। এর মধ্যে: আয়াতুল কুরসী; তিনটি কুল প্রতিটি তিনবার, হাতের তালুতে ফুঁ দিয়ে; "হাসবিয়াল্লাহু লা ইলাহা ইল্লা হুয়া, আলাইহি তাওয়াক্কালতু ওয়া হুয়া রব্বুল-আরশিল-আজীম" (সাত বার); এবং "আল্লাহুম্মা বিকা আসবাহনা ওয়া বিকা আমসায়না..."। সকালের জিকির শেষ করার পর সূর্যোদয় পর্যন্ত নামাজের জায়গায় বসে থাকুন, তারপর দুই রাকাত "ইশরাক" পড়ুন; নবী ﷺ বলেছেন এটি একটি পূর্ণ হজ ও উমরাহর সওয়াব বহন করে।`, fas: `پس از سلام فرض، علاوه بر اذکار عمومی پس از نماز: زمان اذکار صبح (أذکار الصباح) فرارسیده و تا طلوع خورشید معتبر است. از جمله: آیة الکرسی؛ سه "قل" هر یک سه بار با دمیدن در کف دست‌ها؛ "حسبي الله لا إله إلا هو علیه توکلت و هو رب العرش العظیم" (هفت بار)؛ "اللهم بک أصبحنا و بک أمسینا...". پس از اتمام اذکار صبح، در محل نماز تا طلوع خورشید نشسته بمان، سپس دو رکعت "اشراق" بخوان؛ پیامبر ﷺ فرمود این پاداش یک حج و عمره کامل را دارد.`, zh: `主命之平安词后，除拜功后通用赞念外：晨间赞念（晨念，adhkar al-sabah）此时到时，至日出仍有效。其中包括：宝座经；三章"qul"各三遍，向掌心吹气；"Hasbiyallahu la ilaha illa huwa…"七遍；"Allahumma bika asbahna wa bika amsayna…"。完成晨念后，于礼拜处坐至日出，再礼两拜"伊什拉格"；先知ﷺ言此具完整朝觐与副朝之回赐。`, yue: `主命之平安詞後，除拜功後通用讚念外：晨間讚念（晨念，adhkar al-sabah）此時到時，至日出仍有效。其中包括：寶座經；三章「qul」各三遍，向掌心吹氣；「Hasbiyallahu la ilaha illa huwa…」七遍；「Allahumma bika asbahna wa bika amsayna…」。完成晨念後，於禮拜處坐至日出，再禮兩拜「伊什拉格」；先知ﷺ言此具完整朝覲與副朝之回賜。`, ja: `ファルドのサラーム後、礼拝後の一般的なズィクルに加えて：朝のズィクル（アズカール・アッ＝サバーハ）の時が今訪れ、日の出までは有効である。その中には：アーヤトゥル＝クルスィー、三つの「クル」各三回ずつ手のひらに息を吹きかけて、「ハスビヤッラーフ・ラー・イラーハ・イッラー・フワ、アライヒ・タワッカルトゥ・ワ・フワ・ラッブル＝アルシル＝アズィーム」（七回）、そして「アッラーフマ・ビカ・アスバフナー・ワ・ビカ・アムサイナー…」。朝のズィクルを終えた後、日の出まで礼拝の場に座り続け、それから二ラクアの「イシュラーク」礼拝を行う；預言者ﷺは、これが完全なハッジとウムラの報奨を持つと仰せられた。`, ru: `После завершающего салама фарда, помимо общих послемолитвенных азкаров: настало время утренних азкаров (азкар ас-сабах), действительных до восхода. Среди них: Аят аль-Курси; три суры «кул» каждая по три раза с дуновением в ладони; «Хасбийаллаху ля иляха илля Хува, 'аляйхи таваккальту ва Хува Рабб аль-'Аршиль-'Азым» (семь раз); «Аллахумма бика асбахна ва бика амсайна…». По окончании утренних азкаров оставайся сидеть на месте молитвы до восхода, затем соверши два раката «Ишрак»; Пророк ﷺ сказал, что это несёт награду полного Хаджа и Умры.`, es: `Tras el salam del fard, además de los adhkar post-oración universales: los adhkar de la mañana (adhkar al-sabah) son ahora debidos y siguen siendo válidos hasta la salida del sol. Entre ellos: Ayat al-Kursi; los tres "qul" cada uno tres veces, soplando en las palmas; "Hasbiyallahu la ilaha illa huwa, 'alayhi tawakkaltu wa huwa Rabbul-'Arshil-'Azim" (siete veces); y "Allahumma bika asbahna wa bika amsayna...". Tras completar los adhkar matinales, permanece sentado en el lugar de oración hasta el amanecer, luego reza dos rak'ahs de "Ishraq"; el Profeta ﷺ dijo que esto lleva la recompensa de un Hajj y Umrah completos.`, ko: `파르드 살람 후, 보편적인 예배 후 아드카르 외에: 아침 아드카르(아드카르 알사바흐)의 시간이 시작되며 일출까지 유효하다. 그중에는: 아야툴 쿠르시; 세 "꿀" 장 각각 세 번씩 손바닥에 입김을 불며; "하스비얄라후 라 일라하 일라 후와, 알라이히 타왁칼투 와 후와 랍불아르쉴아짐"(일곱 번); "알라훔마 비카 아스바흐나 와 비카 암사이나…". 아침 아드카르를 마친 뒤, 일출까지 예배 자리에 앉아 있다가 두 라카의 "이슈라끄"를 예배하라; 예언자 ﷺ께서는 이것이 완전한 핫즈와 우므라의 보상을 가진다고 말씀하셨다.`, ta: `ஃபர்ளின் ஸலாமுக்குப் பின், பொதுவான தொழுகைக்குப் பின்தைய திக்ருகள் தவிர: காலை திக்ருகளுக்கான (அத்காரு அஸ்-ஸபாஹ்) வேளை இப்போது வந்துவிட்டது, சூரிய உதயம் வரை செல்லும். அவற்றில்: ஆயத்துல் குர்ஸி; மூன்று "குல்" ஒவ்வொன்றும் மூன்று முறை, உள்ளங்கைகளில் ஊதி; "ஹஸ்பியல்லாஹு லா இலாஹ இல்லா ஹுவ, அலைஹி தவக்கல்து வ ஹுவ ரப்புல்-அர்ஷில்-அழீம்" (ஏழு முறை); மற்றும் "அல்லாஹும்ம பிக அஸ்பஹ்னா வ பிக அம்ஸைனா...". காலை திக்ருகளை முடித்த பிறகு, சூரிய உதயம் வரை தொழுகை இடத்தில் அமர்ந்திருங்கள், பின் இரண்டு ரக்அத் "இஷ்ராக்" தொழுங்கள்; நபி ﷺ இது ஒரு முழுமையான ஹஜ் மற்றும் உம்ராவின் கூலியைச் சுமக்கிறது எனக் கூறினார்.`, si: `ෆර්ද් සලාම් පසු, සලාතයෙන් පසු සාර්වත්‍රික දික්ර්වලට අමතරව: උදෑසන දික්ර්වල (අද්කාර් අස්-සබාහ්) කාලය දැන් පැමිණී ඇත, හිරු උදාව දක්වා වලංගුව පවතී. ඒවා අතර: ආයතුල් කුර්සී; "කුල්" තුන බැගින් තුන් වරක්, අල්ල තුළට පිඹ; "හස්බියල්ලාහු ලා ඉලාහ ඉල්ලා හුව, අලෛහි තවක්කල්තු ව හුව රබ්බුල්-අර්ෂිල්-අසීම්" (හත් වරක්); සහ "අල්ලාහුම්ම බික අස්බහ්නා ව බික අම්සෛනා...". උදෑසන දික්ර් අවසන් කළ පසු, හිරු උදාව දක්වා සලාත් කළ ස්ථානයේ වාඩි වී සිට, පසුව රකඅත් දෙකක "ඉෂ්රාක්" සලාත් කරන්න; නබි ﷺ එය සම්පූර්ණ හජ් සහ උම්රාවේ ප්‍රතිඵලය දරන බව පැවසූහ.` },
  fajr_virtues: { en: `Praying Fajr in congregation has the reward of standing the entire night in prayer (Muslim 656). Standing in prayer between Fajr and sunrise is described by the Prophet ﷺ as "more beloved to me than freeing four slaves." The morning hours after Fajr are blessed: the Prophet ﷺ supplicated, "O Allah, bless my nation in their early mornings." The hypocrites are identified by their inability to attend Fajr  –  "the heaviest prayers on the hypocrites are Isha and Fajr; if they knew what they contain, they would crawl to them." (Bukhari 657, Muslim 651).`, ms: `Mendirikan Subuh secara berjemaah membawa pahala berdiri solat sepanjang malam (Muslim 656). Berdiri solat antara Subuh dan matahari terbit disifatkan oleh Nabi ﷺ sebagai "lebih dicintai olehku daripada memerdekakan empat hamba." Waktu pagi selepas Subuh diberkati: Nabi ﷺ berdoa, "Ya Allah, berkatilah umatku pada awal pagi mereka." Munafik dikenali daripada ketidakmampuan mereka menghadiri Subuh  –  "solat yang paling berat ke atas munafik ialah Isyak dan Subuh; jika mereka tahu apa yang ada padanya, nescaya mereka akan datang merangkak." (Bukhari 657, Muslim 651).`, tur: `Sabah'ı cemaatle kılmak, bütün geceyi namazda geçirmenin sevabını taşır (Müslim 656). Sabah ile güneşin doğuşu arasında namazda durmak Peygamber'in ﷺ "dört köle azat etmekten daha sevimli" gördüğü ameldir. Sabahtan sonraki saatler bereketlidir: Peygamber ﷺ "Allah'ım, ümmetimi erken sabahlarında bereketlendir." diye dua etti. Münafıklar Sabah'a gelememeleriyle tanınır  –  "münafıklara en ağır gelen iki namaz Yatsı ve Sabah'tır; içinde olanı bilselerdi sürünerek bile gelirlerdi." (Buhârî 657, Müslim 651).`, urd: `فجر کو باجماعت پڑھنا پوری رات قیام کرنے کا ثواب رکھتا ہے (مسلم ۶۵۶)۔ نبی ﷺ نے فجر اور طلوعِ آفتاب کے درمیان نماز کھڑے ہو کر پڑھنے کو "چار غلام آزاد کرنے سے زیادہ محبوب" قرار دیا۔ فجر کے بعد کے صبح کے اوقات بابرکت ہیں: نبی ﷺ نے دعا فرمائی، "اے اللہ! میری امت کے لیے ان کی صبح کے اوقات میں برکت دے۔" منافقوں کی پہچان فجر میں حاضر نہ ہونا ہے  –  "منافقین پر سب سے بھاری دو نمازیں عشاء اور فجر ہیں؛ اگر وہ جان لیں کہ ان میں کیا ہے، تو گھٹنوں کے بل بھی آ جائیں۔" (بخاری ۶۵۷، مسلم ۶۵۱)۔`, ben: `ফজর জামাতে আদায় করা পুরো রাত নামাজে দাঁড়িয়ে থাকার সওয়াব বহন করে (মুসলিম ৬৫৬)। ফজর ও সূর্যোদয়ের মাঝে নামাজে দাঁড়ানোকে নবী ﷺ "চারজন দাসকে মুক্ত করার চেয়েও আমার কাছে প্রিয়" বলেছেন। ফজরের পরের সকালের সময়গুলো বরকতময়: নবী ﷺ দোয়া করেছেন, "হে আল্লাহ! আমার উম্মতকে তাদের সকালের শুরুতে বরকত দাও।" মুনাফিকদের চেনা যায় তাদের ফজরে উপস্থিত হতে না পারা দিয়ে  –  "মুনাফিকদের উপর সবচেয়ে ভারী দুটি নামাজ ইশা ও ফজর; যদি তারা জানত এতে কী আছে, তারা হামাগুড়ি দিয়েও আসত।" (বুখারি ৬৫৭, মুসলিম ৬৫১)।`, fas: `گزاردن نماز فجر به جماعت پاداش قیام تمام شب را دارد (مسلم ۶۵۶). ایستادن در نماز میان فجر و طلوع را پیامبر ﷺ "نزد من از آزاد کردن چهار بنده محبوب‌تر" خواند. ساعات صبح پس از فجر مبارک‌اند: پیامبر ﷺ دعا فرمود، "خدایا، در صبح زود امتم برکت قرار ده." منافقان به ناتوانی از حضور در فجر شناخته می‌شوند  –  "سنگین‌ترین دو نماز بر منافقان عشاء و فجر است؛ اگر می‌دانستند در آنها چیست، حتی به سینه‌خیز هم می‌آمدند." (بخاری ۶۵۷، مسلم ۶۵۱).`, zh: `集体礼晨礼具有彻夜立礼之回赐（穆斯林656）。先知ﷺ言介乎晨礼与日出之间的立礼"于我比释放四名奴隶更可爱"。晨礼后之晨时蒙福：先知ﷺ祈祷"主啊，求你在我民众清早之时降福"。伪信者以无能赴晨礼而显形  –  "对伪信者最沉重的两次拜功是宵礼与晨礼；他们若知其中内涵，必将匍匐而来。"（布哈里657，穆斯林651）`, yue: `集體禮晨禮具有徹夜立禮之回賜（穆斯林656）。先知ﷺ言介乎晨禮與日出之間嘅立禮「於我比釋放四名奴隸更可愛」。晨禮後嘅晨時蒙福：先知ﷺ祈禱「主啊，求祢喺我民眾清早之時降福」。偽信者以無能赴晨禮而顯形  –  「對偽信者最沉重嘅兩次拜功係宵禮與晨禮；佢哋若知其中內涵，必將匍匐而嚟。」（布哈里657，穆斯林651）`, ja: `ファジュルを集団で行うことには夜通し礼拝に立つ報奨がある（ムスリム656）。預言者ﷺはファジュルから日の出までの礼拝の立位を「私にとって四人の奴隷を解放するよりも愛しい」と仰せられた。ファジュル後の朝の時間は祝福される：預言者ﷺは祈った、「アッラーよ、わが民の朝早くに祝福を与え給え」。偽善者はファジュルに出席できないことで識別される  –  「偽善者にとって最も重い二つの礼拝はイシャーとファジュルである。その中身を知っていたなら、彼らは這ってでも来ただろう。」（ブハーリー657、ムスリム651）`, ru: `Совершение Фаджра в коллективе несёт награду стояния всю ночь в молитве (Муслим 656). Стояние в молитве между Фаджром и восходом Пророк ﷺ называл «более любимым для меня, чем освобождение четырёх рабов». Утренние часы после Фаджра благословенны: Пророк ﷺ молил, «О Аллах, благослови мою общину в их раннее утро». Лицемеры узнаются по неспособности явиться на Фаджр  –  «самые тяжкие для лицемеров две молитвы — Иша и Фаджр; если бы они знали, что в них, они приползли бы к ним.» (Бухари 657, Муслим 651).`, es: `Rezar el Fajr en congregación tiene la recompensa de permanecer toda la noche en oración (Muslim 656). El Profeta ﷺ describió el orar entre el Fajr y el amanecer como "más amado para mí que liberar a cuatro esclavos." Las horas matutinas tras el Fajr son benditas: el Profeta ﷺ suplicó, "Oh Allah, bendice a mi nación en sus madrugadas." Los hipócritas se identifican por su incapacidad para asistir al Fajr  –  "las oraciones más pesadas para los hipócritas son el Isha y el Fajr; si supieran lo que contienen, vendrían a gatas." (Bujari 657, Muslim 651).`, ko: `파즈르를 회중으로 예배하는 것은 밤새 예배에 서 있는 보상을 가집니다(무슬림 656). 파즈르와 일출 사이에 예배에 서는 것을 예언자 ﷺ께서는 "네 명의 노예를 해방하는 것보다 내게 더 사랑스럽다"고 묘사하셨다. 파즈르 이후의 아침 시간은 축복받았다: 예언자 ﷺ께서 기도하셨다, "오 알라, 제 공동체에게 그들의 이른 아침에 축복을 주소서." 위선자는 파즈르에 참석하지 못함으로 식별된다  –  "위선자들에게 가장 무거운 두 예배는 이샤와 파즈르이다; 그들이 그 안에 무엇이 있는지 알았더라면 기어서라도 왔을 것이다." (부카리 657, 무슬림 651).`, ta: `ஃபஜ்ரை கூட்டாகத் தொழுவது இரவு முழுவதும் தொழுகையில் நிற்கும் கூலியைச் சுமக்கிறது (முஸ்லிம் 656). ஃபஜ்ருக்கும் சூரிய உதயத்திற்கும் இடையே தொழுகையில் நிற்பதை நபி ﷺ "எனக்கு நான்கு அடிமைகளை விடுவிப்பதை விட விரும்பப்படுவது" எனக் கூறினார். ஃபஜ்ருக்குப் பின்னான காலை வேளைகள் பாக்கியமானவை: நபி ﷺ துஆ செய்தார், "அல்லாஹ்வே! என் சமுதாயத்தினருக்கு அவர்களின் அதிகாலையில் பாக்கியம் அளி." நயவஞ்சகர்கள் ஃபஜ்ரில் கலந்துகொள்ள இயலாமையால் அடையாளம் காணப்படுகிறார்கள்  –  "நயவஞ்சகர்கள் மீது மிக கடினமான இரு தொழுகைகள் இஷாவும் ஃபஜ்ரும்; அவற்றில் என்ன உள்ளது என அவர்கள் அறிந்திருந்தால், ஊர்ந்தாவது வந்திருப்பார்கள்." (புகாரி 657, முஸ்லிம் 651).`, si: `ෆජ්ර් සමූහ වශයෙන් ඉටු කිරීම මුළු රාත්‍රියම සලාතයේ සිටීමේ ප්‍රතිඵලය දරයි (මුස්ලිම් 656). නබි ﷺ ෆජ්ර් සහ හිරු උදාව අතර සලාතයේ සිටීම "මට වහල්ලු සිවුදෙනෙකු නිදහස් කිරීමට වඩා ප්‍රිය" යැයි විස්තර කළහ. ෆජ්ර්ට පසු උදෑසන වේලාවන් ආශීර්වාද ලත්ය: නබි ﷺ ප්‍රාර්ථනා කළහ, "අල්ලාහ්වනේ, මාගේ සමාජයේ අයට ඔවුන්ගේ අලුයමේදී ආශීර්වාද කරන්න." කපටියන් හඳුනා ගනු ලබන්නේ ඔවුන්ට ෆජ්ර්ට පැමිණීමට නොහැකි වීමෙනි  –  "කපටියන්ට බරම සලාත දෙක ඉෂා සහ ෆජ්ර්; ඒවායේ ඇති දේ ඔවුන් දන්නේ නම්, බඩගා හෝ ඔවුහු ඊට පැමිණෙනු ඇත." (බුහාරි 657, මුස්ලිම් 651).` },
  fajr_timing_notes: { en: `Avoid praying any voluntary prayer (other than greeting the mosque or the omitted Sunnah al-Fajr) from sunrise until the sun has fully risen and risen "the height of a spear" (approximately 15-20 minutes after sunrise). If a person misses Fajr by sleep or genuine forgetfulness, he prays it as soon as he wakes  –  the Prophet ﷺ did this once on a journey when the army overslept, and said: "There is no failure (lit. 'no negligence') in sleep; failure is in wakefulness." (Muslim 681). The two Sunnah rak'ahs can also be prayed immediately after the fard if missed beforehand, or after sunrise (Tirmidhi 423).`, ms: `Elakkan menunaikan sebarang solat sunat (selain tahiyyat masjid atau Sunnah Subuh yang tertinggal) dari matahari terbit hingga matahari naik sepenuhnya "setinggi tombak" (kira-kira 15-20 minit selepas terbit). Jika seseorang terlepas Subuh kerana tidur atau lupa, dia mendirikannya sebaik sahaja terjaga  –  Nabi ﷺ pernah berbuat demikian dalam satu perjalanan apabila tentera tertidur, dan bersabda: "Tiada kelalaian dalam tidur; kelalaian adalah ketika sedar." (Muslim 681). Dua rakaat sunat juga boleh dilakukan sebaik selepas fardu jika tertinggal sebelumnya, atau selepas matahari terbit (Tirmidhi 423).`, tur: `Güneşin doğuşundan, güneş tamamen yükselip "bir mızrak boyu" yükselene kadar (yaklaşık 15-20 dakika) hiçbir nafile namaz kılınmaz (mescide selâm ve kaçırılmış Sabah sünneti hariç). Bir kimse Sabah'ı uyku veya gerçek unutkanlıkla kaçırırsa, uyandığı anda kılar  –  Peygamber ﷺ bir seferde ordu uyuyakaldığında bunu yapmış ve "Uykuda kusur yoktur; kusur uyanıklıkta olur" buyurmuştur (Müslim 681). İki rekât sünnet de farzdan hemen sonra kılınabilir veya güneş doğduktan sonra kaza edilebilir (Tirmizî 423).`, urd: `طلوعِ آفتاب سے سورج کے مکمل بلند ہونے اور "نیزے کے قد" تک بلند ہونے (تقریباً ۱۵-۲۰ منٹ بعد) تک کوئی نفل نماز نہ پڑھیں (تحیة المسجد یا قضا شدہ سنّت الفجر کے علاوہ)۔ اگر کوئی نیند یا حقیقی بھول کے باعث فجر چھوڑ دے تو جاگتے ہی پڑھے  –  نبی ﷺ نے ایک سفر میں جب لشکر سو گیا تو ایسا کیا اور فرمایا: "نیند میں کوئی کوتاہی نہیں؛ کوتاہی بیداری میں ہے۔" (مسلم ۶۸۱)۔ دو سنّت رکعات بھی فرض کے فوراً بعد ادا کی جا سکتی ہیں اگر پہلے رہ گئی ہوں، یا طلوعِ آفتاب کے بعد (ترمذی ۴۲۳)۔`, ben: `সূর্যোদয় থেকে সূর্য পূর্ণরূপে উঠে "একটি বর্শার উচ্চতা" পর্যন্ত (সূর্যোদয়ের প্রায় ১৫-২০ মিনিট পর) কোনো নফল নামাজ পড়বেন না (মসজিদকে অভিবাদন বা ছুটে যাওয়া সুন্নাহ আল-ফজর ব্যতীত)। কেউ যদি ঘুম বা প্রকৃত ভুলে ফজর ছুটিয়ে ফেলে, সে জেগে উঠেই পড়বে  –  নবী ﷺ একবার সফরে যখন বাহিনী ঘুমিয়ে পড়ল তখন এমন করেছিলেন এবং বলেছিলেন: "ঘুমে কোনো অবহেলা নেই; অবহেলা জাগরণে।" (মুসলিম ৬৮১)। দুই সুন্নাহ রাকাত আগে ছুটে গেলে ফরজের পরপরই, বা সূর্যোদয়ের পরে আদায় করা যায় (তিরমিযি ৪২৩)।`, fas: `از طلوع خورشید تا کاملاً برآمدن و رسیدن آن به اندازه "قامت یک نیزه" (تقریباً ۱۵-۲۰ دقیقه پس از طلوع) هیچ نماز نافله نخوان (به جز تحیة المسجد یا سنت فوت‌شده فجر). اگر کسی فجر را با خواب یا فراموشی واقعی از دست داد، به محض بیداری بخواند  –  پیامبر ﷺ یک بار در سفری چنین کرد و فرمود: "در خواب کوتاهی نیست؛ کوتاهی در بیداری است." (مسلم ۶۸۱). دو رکعت سنت را نیز اگر پیش از فرض از دست رفت می‌توان بلافاصله پس از فرض یا پس از طلوع خواند (ترمذی ۴۲۳).`, zh: `自日出至太阳完全升起、升至"一矛之高"（约日出后15-20分钟）期间，勿礼任何副功拜（除问候清真寺或补晨礼前圣行外）。若有人因睡眠或真正的遗忘而错过晨礼，应一醒来即礼  –  先知ﷺ曾在一次旅途中军队过睡时如此行，并说："睡眠中无怠惰；怠惰在醒时。"（穆斯林681）。两拜圣行若于主命前漏礼，可于主命之后立即补礼，或日出之后补礼（提尔米兹423）。`, yue: `自日出至太陽完全升起、升至「一矛之高」（約日出後15-20分鐘）期間，勿禮任何副功拜（除問候清真寺或補晨禮前聖行外）。若有人因睡眠或真正嘅遺忘而錯過晨禮，應一醒嚟即禮  –  先知ﷺ曾喺一次旅途中軍隊過睡時如此行，並話：「睡眠中無怠惰；怠惰喺醒時。」（穆斯林681）。兩拜聖行若於主命前漏禮，可於主命之後立即補禮，或日出之後補禮（提爾米茲423）。`, ja: `日の出から、太陽が完全に昇り「槍一本の高さ」になるまで（日の出後約15～20分）、任意の礼拝（モスクへの挨拶か逃したスンナ・アル＝ファジュルを除く）を行わない。眠りや真の忘却によってファジュルを逃した場合は、目覚めたらすぐに行う  –  預言者ﷺは旅で軍が寝過ごした際にそうし、「眠りには怠慢はない。怠慢は目覚めにある」と仰せられた（ムスリム681）。二ラクアのスンナも、ファルド前に逃した場合はファルドの直後に、または日の出後に補える（ティルミズィー423）。`, ru: `Не совершай никакой добровольной молитвы (кроме приветствия мечети или пропущенной сунны Фаджра) с восхода солнца до полного его подъёма «на высоту копья» (примерно через 15–20 минут после восхода). Если человек пропустил Фаджр из-за сна или подлинной забывчивости, он совершает её, как только проснётся  –  Пророк ﷺ так сделал однажды в пути, когда войско проспало, и сказал: «В сне нет небрежности; небрежность  –  в бодрствовании.» (Муслим 681). Два раката сунны также можно совершить сразу после фарда, если пропущены ранее, или после восхода (Тирмизи 423).`, es: `Evita rezar cualquier oración voluntaria (salvo el saludo a la mezquita o la Sunnah al-Fajr omitida) desde el amanecer hasta que el sol haya salido por completo y se haya elevado "la altura de una lanza" (aproximadamente 15-20 minutos tras el amanecer). Si una persona pierde el Fajr por sueño o por un olvido genuino, lo reza tan pronto como despierte  –  el Profeta ﷺ lo hizo una vez en un viaje cuando el ejército se quedó dormido, y dijo: "No hay negligencia en el sueño; la negligencia está en la vigilia." (Muslim 681). Los dos rak'ahs Sunnah también pueden rezarse inmediatamente después del fard si se omitieron antes, o tras el amanecer (Tirmidhi 423).`, ko: `일출부터 태양이 완전히 떠올라 "창 하나의 높이"가 될 때까지(일출 후 약 15~20분) 자발 예배(모스크 인사 또는 놓친 순나 알파즈르 제외)는 행하지 말라. 누군가 잠이나 진정한 망각으로 파즈르를 놓쳤다면, 깨는 즉시 예배한다  –  예언자 ﷺ께서는 여행 중 군대가 늦잠 잤을 때 이를 행하시며 "잠에는 태만이 없다; 태만은 깨어 있을 때이다"고 말씀하셨다 (무슬림 681). 두 순나 라카도 미리 놓쳤다면 파르드 직후나 일출 후에 보충할 수 있다 (티르미디 423).`, ta: `சூரிய உதயத்திலிருந்து சூரியன் முழுமையாக ஏறி "ஒரு ஈட்டியின் உயரம்" (சூரிய உதயத்திற்குப் பின் சுமார் 15-20 நிமிடங்கள்) வரை எந்த நஃபில் தொழுகையையும் தொழ வேண்டாம் (பள்ளி வாழ்த்து அல்லது தவறிய ஃபஜ்ர் சுன்னா தவிர). ஒருவர் தூக்கம் அல்லது உண்மையான மறதியால் ஃபஜ்ரை இழந்தால், விழித்தவுடனேயே தொழுகிறார்  –  ஒரு பயணத்தில் படை அதிக நேரம் தூங்கியபோது நபி ﷺ இவ்வாறு செய்தார், கூறினார்: "தூக்கத்தில் அலட்சியம் இல்லை; அலட்சியம் விழிப்பில் உள்ளது." (முஸ்லிம் 681). இரு சுன்னா ரக்அத்களையும் முன்னர் தவறியிருந்தால் ஃபர்ளுக்குப் பிறகு உடனடியாகவோ, சூரிய உதயத்திற்குப் பிறகோ தொழலாம் (திர்மிதி 423).`, si: `හිරු උදාවේ සිට හිරු සම්පූර්ණයෙන් ඉහළ නැගී "ඇවැස්මක උස" දක්වා (හිරු උදාවට පසු මිනිත්තු 15-20ක් පමණ) කිසිදු ස්වේච්ඡා සලාතයක් (මස්ජිදයට ආචාර කිරීම හෝ අතපසු වූ සුන්නා අල්-ෆජ්ර් හැර) නොකරන්න. කෙනෙකු නින්දෙන් හෝ සැබෑ අමතකකමින් ෆජ්ර් මඟ හැරුණොත්, අවදි වූ විගසම එය ඉටු කරයි  –  නබි ﷺ එක් ගමනක දී හමුදාව අධික නින්දට ගිය විට මෙය කළ අතර පැවසූහ: "නින්දේදී නොසැලකිල්ලක් නැත; නොසැලකිල්ල ඇත්තේ අවදිවෙහි." (මුස්ලිම් 681). සුන්නා රකඅත් දෙකද කලින් මඟ හැරුණොත් ෆර්ද්ට පසු වහාම හෝ හිරු උදාවට පසු ඉටු කළ හැක (තිර්මිදී 423).` },
} satisfies Record<string, LangMap>;
